  function normalizeFontFileName(name){
    return String(name || '').trim().toLowerCase();
  }

  function fontDefinitionForFile(name){
    const normalized = normalizeFontFileName(name);
    return USER_FONT_DEFINITIONS.find(definition => {
      const original = definition.originalFileName || definition.fileName;
      return normalizeFontFileName(original) === normalized;
    }) || null;
  }

  function fontDefinitionForValue(fontValue){
    const value = String(fontValue || '');
    return USER_FONT_DEFINITIONS.find(
      definition => value.includes(definition.family)
    ) || null;
  }

  function selectedUserFontDefinitions(){
    const definitions = ['titleFont', 'bodyFont', 'metaFont']
      .map(id => fontDefinitionForValue($(id)?.value))
      .filter(Boolean);

    return [...new Map(
      definitions.map(definition => [definition.fileName, definition])
    ).values()];
  }

  function updateCustomFontStatus(message, kind=''){
    const status = $('customFontStatus');
    if(!status) return;
    status.classList.remove('font-ok', 'font-warn');
    if(kind) status.classList.add(kind);
    status.textContent = message;
  }

  function stripFontExtension(fileName){
    return String(fileName || '').replace(/\.(otf|ttf|woff2?|ttc)$/i, '');
  }

  function readableFontLabel(fileName){
    const label = stripFontExtension(fileName)
      .replace(/[_-]+/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();
    return label || '사용자 폰트';
  }

  function inferFontWeight(fileName){
    const name = String(fileName || '').toLowerCase();
    if(/thin|hairline|100/.test(name)) return '100';
    if(/extra.?light|ultra.?light|200/.test(name)) return '200';
    if(/light|300/.test(name)) return '300';
    if(/medium|500/.test(name)) return '500';
    if(/semi.?bold|demi.?bold|600/.test(name)) return '600';
    if(/extra.?bold|ultra.?bold|800/.test(name)) return '800';
    if(/black|heavy|900/.test(name)) return '900';
    if(/bold|700/.test(name)) return '700';
    return '400';
  }

  function inferFontFallback(fileName){
    const name = String(fileName || '').toLowerCase();
    return /serif|batang|myeongjo|명조|바탕/.test(name)
      ? 'serif'
      : 'sans-serif';
  }

  function createCustomFontId(){
    if(globalThis.crypto?.randomUUID){
      return crypto.randomUUID().replaceAll('-', '');
    }
    return `${Date.now().toString(36)}${Math.random().toString(36).slice(2)}`;
  }

  function customFontValue(definition){
    return `'${definition.family}', ${definition.fallback || 'sans-serif'}`;
  }

  function sanitizeCustomDefinition(record){
    if(!record || !record.fileName || !record.family) return null;
    return {
      fileName:String(record.fileName),
      originalFileName:String(record.originalFileName || record.fileName),
      family:String(record.family),
      label:String(record.label || readableFontLabel(record.originalFileName || record.fileName)),
      weight:String(record.weight || '400'),
      fallback:String(record.fallback || inferFontFallback(record.originalFileName || record.fileName)),
      custom:true,
      createdAt:Number(record.createdAt || Date.now()),
      sizeBytes:Number(record.sizeBytes || 0)
    };
  }

  function findCustomFontGroup(select){
    return [...select.children].find(
      child => child.tagName === 'OPTGROUP' && child.dataset.customFontGroup === 'true'
    ) || null;
  }

  function ensureCustomFontGroup(select){
    let group = findCustomFontGroup(select);
    if(!group){
      group = document.createElement('optgroup');
      group.label = CUSTOM_FONT_GROUP_LABEL;
      group.dataset.customFontGroup = 'true';
      select.appendChild(group);
    }
    return group;
  }

  function addFontOption(definition){
    if(!definition.custom) return;
    const value = customFontValue(definition);

    ['titleFont', 'bodyFont', 'metaFont'].forEach(id => {
      const select = $(id);
      if(!select) return;
      const existing = [...select.options].find(option => option.value === value);
      if(existing){
        existing.textContent = definition.label;
        existing.dataset.fontKey = definition.fileName;
        return;
      }

      const option = document.createElement('option');
      option.value = value;
      option.textContent = definition.label;
      option.dataset.fontKey = definition.fileName;
      ensureCustomFontGroup(select).appendChild(option);
    });
  }

  function removeFontOptions(definition){
    const value = customFontValue(definition);
    ['titleFont', 'bodyFont', 'metaFont'].forEach(id => {
      const select = $(id);
      if(!select) return;
      [...select.options]
        .filter(option => option.value === value || option.dataset.fontKey === definition.fileName)
        .forEach(option => option.remove());
      const group = findCustomFontGroup(select);
      if(group && !group.children.length) group.remove();
    });
  }

  function registerCustomFontDefinition(rawDefinition, {persist=true}={}){
    const definition = sanitizeCustomDefinition(rawDefinition);
    if(!definition) return null;

    const existing = USER_FONT_DEFINITIONS.find(
      item => item.fileName === definition.fileName || item.family === definition.family
    );

    if(existing){
      Object.assign(existing, definition);
      const catalogExisting = customFontCatalog.find(item => item.fileName === definition.fileName);
      if(catalogExisting) Object.assign(catalogExisting, definition);
      else customFontCatalog.push(definition);
      addFontOption(existing);
      if(persist) saveCustomFontCatalog();
      return existing;
    }

    USER_FONT_DEFINITIONS.push(definition);
    customFontCatalog.push(definition);
    addFontOption(definition);
    if(persist) saveCustomFontCatalog();
    return definition;
  }

  function saveCustomFontCatalog(){
    try{
      const serializable = customFontCatalog.map(definition => ({
        fileName:definition.fileName,
        originalFileName:definition.originalFileName,
        family:definition.family,
        label:definition.label,
        weight:definition.weight,
        fallback:definition.fallback,
        custom:true,
        createdAt:definition.createdAt,
        sizeBytes:definition.sizeBytes
      }));
      localStorage.setItem(CUSTOM_FONT_CATALOG_KEY, JSON.stringify(serializable));
    }catch(error){}
  }

  function restoreCustomFontCatalog(){
    try{
      const records = JSON.parse(localStorage.getItem(CUSTOM_FONT_CATALOG_KEY) || '[]');
      if(!Array.isArray(records)) return;
      records.forEach(record => registerCustomFontDefinition(record, {persist:false}));
      saveCustomFontCatalog();
    }catch(error){
      customFontCatalog = [];
    }
    renderCustomFontList();
  }

  function formatFontSize(bytes){
    const size = Number(bytes || 0);
    if(!size) return '용량 정보 없음';
    if(size < 1024 * 1024) return `${Math.max(1, Math.round(size / 1024))} KB`;
    return `${(size / (1024 * 1024)).toFixed(size >= 10 * 1024 * 1024 ? 1 : 2)} MB`;
  }

  function renderCustomFontList(){
    const list = $('customFontList');
    if(!list) return;
    list.replaceChildren();

    const fonts = [...customFontCatalog].sort((a,b) => a.createdAt - b.createdAt);
    if(!fonts.length){
      const empty = document.createElement('div');
      empty.className = 'custom-font-empty';
      empty.textContent = '사용자가 추가한 폰트가 없습니다. 위에서 폰트 파일을 선택하면 세 개의 폰트 목록에 자동으로 추가됩니다.';
      list.appendChild(empty);
      return;
    }

    fonts.forEach(definition => {
      const item = document.createElement('div');
      item.className = 'custom-font-item';
      item.dataset.customFontKey = definition.fileName;

      const head = document.createElement('div');
      head.className = 'custom-font-item-head';

      const name = document.createElement('input');
      name.className = 'custom-font-name';
      name.value = definition.label;
      name.dataset.customFontRename = definition.fileName;
      name.setAttribute('aria-label', `${definition.label} 표시 이름`);

      const remove = document.createElement('button');
      remove.type = 'button';
      remove.className = 'custom-font-delete';
      remove.dataset.customFontDelete = definition.fileName;
      remove.textContent = '삭제';

      head.append(name, remove);

      const meta = document.createElement('div');
      meta.className = 'custom-font-meta';

      const file = document.createElement('span');
      file.textContent = definition.originalFileName;
      const size = document.createElement('span');
      size.className = 'custom-font-chip';
      size.textContent = formatFontSize(definition.sizeBytes);
      const weight = document.createElement('span');
      weight.className = 'custom-font-chip';
      weight.textContent = `Weight ${definition.weight}`;

      meta.append(file, size, weight);
      item.append(head, meta);
      list.appendChild(item);
    });
  }

  function openFontDatabase(){
    return new Promise((resolve, reject) => {
      if(!('indexedDB' in window)){
        reject(new Error('IndexedDB unavailable'));
        return;
      }

      const request = indexedDB.open(FONT_DB_NAME, 1);

      request.onupgradeneeded = () => {
        const database = request.result;
        if(!database.objectStoreNames.contains(FONT_DB_STORE)){
          database.createObjectStore(FONT_DB_STORE, {keyPath:'fileName'});
        }
      };

      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(
        request.error || new Error('Font database open failed')
      );
    });
  }

  async function saveUserFontRecord(definition, buffer){
    const database = await openFontDatabase();

    try{
      await new Promise((resolve, reject) => {
        const transaction = database.transaction(FONT_DB_STORE, 'readwrite');

        transaction.objectStore(FONT_DB_STORE).put({
          fileName:definition.fileName,
          originalFileName:definition.originalFileName || definition.fileName,
          family:definition.family,
          label:definition.label,
          weight:definition.weight,
          fallback:definition.fallback || 'sans-serif',
          custom:!!definition.custom,
          createdAt:definition.createdAt || Date.now(),
          sizeBytes:definition.sizeBytes || buffer?.byteLength || 0,
          buffer
        });

        transaction.oncomplete = resolve;
        transaction.onerror = () => reject(
          transaction.error || new Error('Font save failed')
        );
      });

      storedUserFontFiles.add(definition.fileName);
      return true;
    }finally{
      database.close();
    }
  }

  async function updateUserFontMetadata(definition){
    const record = await getUserFontRecord(definition.fileName);
    if(!record) return false;
    await saveUserFontRecord(definition, record.buffer);
    return true;
  }

  async function getUserFontRecord(fileName){
    const database = await openFontDatabase();

    try{
      return await new Promise((resolve, reject) => {
        const transaction = database.transaction(FONT_DB_STORE, 'readonly');
        const request = transaction.objectStore(FONT_DB_STORE).get(fileName);

        request.onsuccess = () => resolve(request.result || null);
        request.onerror = () => reject(
          request.error || new Error('Font read failed')
        );
      });
    }finally{
      database.close();
    }
  }

  async function getAllUserFontRecords(){
    const database = await openFontDatabase();
    try{
      return await new Promise((resolve, reject) => {
        const transaction = database.transaction(FONT_DB_STORE, 'readonly');
        const request = transaction.objectStore(FONT_DB_STORE).getAll();
        request.onsuccess = () => resolve(request.result || []);
        request.onerror = () => reject(request.error || new Error('Font records read failed'));
      });
    }finally{
      database.close();
    }
  }

  async function deleteUserFontRecord(fileName){
    const database = await openFontDatabase();
    try{
      await new Promise((resolve, reject) => {
        const transaction = database.transaction(FONT_DB_STORE, 'readwrite');
        transaction.objectStore(FONT_DB_STORE).delete(fileName);
        transaction.oncomplete = resolve;
        transaction.onerror = () => reject(transaction.error || new Error('Font delete failed'));
      });
    }finally{
      database.close();
    }
  }

  async function readStoredFontRecords(){
    try{
      const records = await getAllUserFontRecords();
      records.forEach(record => {
        storedUserFontFiles.add(String(record.fileName));
        if(record.custom){
          registerCustomFontDefinition(record, {persist:false});
        }
      });
      saveCustomFontCatalog();
      renderCustomFontList();
      return records.length;
    }catch(error){
      return 0;
    }
  }

  async function loadFontBuffer(definition, buffer){
    if(!('FontFace' in window)){
      throw new Error('FontFace API unavailable');
    }

    const previousFace = loadedFontFaces.get(definition.fileName);
    if(previousFace){
      try{ document.fonts.delete(previousFace); }catch(error){}
    }

    const face = new FontFace(
      definition.family,
      buffer,
      {
        style:'normal',
        weight:definition.weight || '400'
      }
    );

    const loadedFace = await face.load();
    document.fonts.add(loadedFace);
    loadedFontFaces.set(definition.fileName, loadedFace);
    loadedUserFonts.add(definition.fileName);
    return true;
  }

  async function loadFontFromAsset(definition){
    if(definition.custom) return false;
    const result = await document.fonts.load(
      `${definition.weight || '400'} 32px '${definition.family}'`,
      '가나다라마바사 ABC 123'
    );

    if(result && result.length){
      loadedUserFonts.add(definition.fileName);
      return true;
    }

    return false;
  }

  async function loadUserFontDefinition(definition){
    if(!definition) return true;
    if(loadedUserFonts.has(definition.fileName)) return true;

    if(fontLoadPromises.has(definition.fileName)){
      return fontLoadPromises.get(definition.fileName);
    }

    const promise = (async () => {
      pendingFontLoads += 1;

      try{
        let record = null;

        try{
          record = await getUserFontRecord(definition.fileName);
        }catch(error){
          record = null;
        }

        if(record?.buffer){
          await loadFontBuffer(definition, record.buffer);
          storedUserFontFiles.add(definition.fileName);
          return true;
        }

        return await loadFontFromAsset(definition);
      }catch(error){
        console.warn(`Font load failed: ${definition.fileName}`, error);
        return false;
      }finally{
        pendingFontLoads = Math.max(0, pendingFontLoads - 1);
        fontLoadPromises.delete(definition.fileName);
      }
    })();

    fontLoadPromises.set(definition.fileName, promise);
    return promise;
  }

  async function ensureSelectedUserFonts({render=true, silent=false}={}){
    const definitions = selectedUserFontDefinitions();

    if(!definitions.length){
      if(!silent && storedUserFontFiles.size){
        updateCustomFontStatus(
          `추가 폰트 ${storedUserFontFiles.size}개가 저장되어 있습니다. 선택할 때만 불러옵니다.`,
          'font-ok'
        );
      }
      if(render) renderPreview();
      return true;
    }

    if(!silent){
      updateCustomFontStatus(
        `선택한 추가 폰트 ${definitions.length}개를 불러오는 중입니다…`
      );
    }

    const results = await Promise.all(
      definitions.map(definition => loadUserFontDefinition(definition))
    );

    const failed = definitions.filter((definition, index) => !results[index]);

    if(failed.length){
      updateCustomFontStatus(
        `폰트 파일을 불러오지 못했습니다: ${failed.map(item => item.label).join(', ')}`,
        'font-warn'
      );
    }else if(!silent){
      updateCustomFontStatus(
        `선택한 추가 폰트 ${definitions.length}개를 적용했습니다.`,
        'font-ok'
      );
    }

    if(render) renderPreview();
    return failed.length === 0;
  }

  async function runWithConcurrency(items, limit, worker){
    const queue = [...items];
    const workers = Array.from(
      {length:Math.min(limit, queue.length)},
      async () => {
        while(queue.length){
          const item = queue.shift();
          await worker(item);
        }
      }
    );

    await Promise.all(workers);
  }

  function existingCustomDefinitionForFile(file){
    const normalized = normalizeFontFileName(file.name);
    return customFontCatalog.find(
      definition => normalizeFontFileName(definition.originalFileName) === normalized
    ) || null;
  }

  function createCustomDefinition(file){
    const id = createCustomFontId();
    return {
      fileName:`custom:${id}`,
      originalFileName:file.name,
      family:`FrameNoteCustom_${id}`,
      label:readableFontLabel(file.name),
      weight:inferFontWeight(file.name),
      fallback:inferFontFallback(file.name),
      custom:true,
      createdAt:Date.now(),
      sizeBytes:file.size
    };
  }

  async function importUserFontFiles(fileList){
    const files = [...(fileList || [])];
    if(!files.length) return;

    const supportedExtensions = /\.(otf|ttf|woff2?|ttc)$/i;
    const validFiles = files.filter(file => supportedExtensions.test(file.name));
    const unsupported = files.filter(file => !supportedExtensions.test(file.name)).map(file => file.name);

    if(!validFiles.length){
      updateCustomFontStatus(
        unsupported.length
          ? `지원하지 않는 파일입니다: ${unsupported.join(', ')}`
          : '선택된 폰트 파일이 없습니다.',
        'font-warn'
      );
      return;
    }

    updateCustomFontStatus(`${validFiles.length}개 폰트를 확인하고 저장하는 중입니다…`);

    let savedCount = 0;
    const failed = [];
    const addedDefinitions = [];

    await runWithConcurrency(validFiles, 2, async file => {
      const predefined = USER_FONT_DEFINITIONS.find(
        definition => !definition.custom && normalizeFontFileName(definition.fileName) === normalizeFontFileName(file.name)
      );
      let definition = predefined || existingCustomDefinitionForFile(file) || createCustomDefinition(file);
      const isNewCustom = !predefined && !customFontCatalog.some(item => item.fileName === definition.fileName);

      try{
        const buffer = await file.arrayBuffer();
        await loadFontBuffer(definition, buffer.slice(0));
        await saveUserFontRecord(definition, buffer.slice(0));

        if(isNewCustom){
          definition = registerCustomFontDefinition(definition) || definition;
          addedDefinitions.push(definition);
        }else if(definition.custom){
          definition.sizeBytes = file.size;
          const catalogDefinition = customFontCatalog.find(item => item.fileName === definition.fileName);
          if(catalogDefinition) catalogDefinition.sizeBytes = file.size;
          saveCustomFontCatalog();
        }

        savedCount += 1;
      }catch(error){
        console.warn(`Font import failed: ${file.name}`, error);
        failed.push(file.name);
      }
    });

    renderCustomFontList();
    renderPreview();

    const messages = [`${savedCount}개 폰트 추가/갱신 완료`];
    if(addedDefinitions.length){
      messages.push('제목·본문·메타 폰트 목록에 추가됨');
    }
    if(unsupported.length){
      messages.push(`지원하지 않는 파일: ${unsupported.join(', ')}`);
    }
    if(failed.length){
      messages.push(`불러오기 실패: ${failed.join(', ')}`);
    }

    updateCustomFontStatus(
      messages.join(' · '),
      unsupported.length || failed.length ? 'font-warn' : 'font-ok'
    );
  }

  async function renameCustomFont(fileName, label){
    const definition = customFontCatalog.find(item => item.fileName === fileName);
    if(!definition) return;
    const cleanLabel = String(label || '').trim() || readableFontLabel(definition.originalFileName);
    definition.label = cleanLabel;
    const runtime = USER_FONT_DEFINITIONS.find(item => item.fileName === fileName);
    if(runtime) runtime.label = cleanLabel;
    addFontOption(definition);
    saveCustomFontCatalog();
    try{ await updateUserFontMetadata(definition); }catch(error){}
    renderCustomFontList();
    updateCustomFontStatus(`폰트 이름을 “${cleanLabel}”로 변경했습니다.`, 'font-ok');
  }

  async function removeCustomFont(fileName){
    const definition = customFontCatalog.find(item => item.fileName === fileName);
    if(!definition) return;
    if(!confirm(`“${definition.label}” 폰트를 삭제할까요?`)) return;

    const value = customFontValue(definition);
    const fallbacks = {
      titleFont:"'Pretendard', sans-serif",
      bodyFont:"'Source Han Sans KR', 'Noto Sans KR', sans-serif",
      metaFont:"'Pretendard', sans-serif"
    };

    Object.entries(fallbacks).forEach(([id, fallback]) => {
      if($(id).value === value) $(id).value = fallback;
    });

    removeFontOptions(definition);
    customFontCatalog = customFontCatalog.filter(item => item.fileName !== fileName);
    const runtimeIndex = USER_FONT_DEFINITIONS.findIndex(item => item.fileName === fileName);
    if(runtimeIndex >= 0) USER_FONT_DEFINITIONS.splice(runtimeIndex, 1);

    const face = loadedFontFaces.get(fileName);
    if(face){
      try{ document.fonts.delete(face); }catch(error){}
    }
    loadedFontFaces.delete(fileName);
    loadedUserFonts.delete(fileName);
    storedUserFontFiles.delete(fileName);
    fontLoadPromises.delete(fileName);

    try{ await deleteUserFontRecord(fileName); }catch(error){}
    saveCustomFontCatalog();
    renderCustomFontList();
    saveState();
    renderPreview();
    updateCustomFontStatus(`“${definition.label}” 폰트를 삭제했습니다.`, 'font-ok');
  }

  function selectedUserFontsAreReady(){
    return selectedUserFontDefinitions().every(
      definition => loadedUserFonts.has(definition.fileName)
    );
  }

  async function initializeUserFonts(){
    const storedCount = await readStoredFontRecords();

    if(storedCount){
      updateCustomFontStatus(
        `추가 폰트 ${storedCount}개가 저장되어 있습니다. 현재 선택한 폰트만 불러옵니다.`,
        'font-ok'
      );
    }

    normalizeFontSelections();
    await ensureSelectedUserFonts({render:false, silent:true});
    renderCustomFontList();
    renderPreview();
  }

  function defaultElementPlacement(){
    return {scale:100, x:0, y:0, lineHeight:100};
  }

  function ensureElementPlacement(layoutName, elementKey){
    if(!elementLayoutState[layoutName]) elementLayoutState[layoutName] = {};
    if(!elementLayoutState[layoutName][elementKey]){
      elementLayoutState[layoutName][elementKey] = defaultElementPlacement();
    }
    const placement = elementLayoutState[layoutName][elementKey];
    if(!Number.isFinite(Number(placement.scale))) placement.scale = 100;
    if(!Number.isFinite(Number(placement.x))) placement.x = 0;
    if(!Number.isFinite(Number(placement.y))) placement.y = 0;
    if(!Number.isFinite(Number(placement.lineHeight))) placement.lineHeight = 100;
    return placement;
  }

  function elementPlacementFromState(state, elementKey){
    const layoutName = state.layout || layout;
    const record = state.elementLayoutState?.[layoutName]?.[elementKey];
    if(!record) return defaultElementPlacement();
    return {
      scale:Number.isFinite(Number(record.scale)) ? Number(record.scale) : 100,
      x:Number.isFinite(Number(record.x)) ? Number(record.x) : 0,
      y:Number.isFinite(Number(record.y)) ? Number(record.y) : 0,
      lineHeight:Number.isFinite(Number(record.lineHeight)) ? Number(record.lineHeight) : 100
    };
  }

  function elementControlValueText(prop, value){
    if(prop === 'scale' || prop === 'lineHeight') return `${value}%`;
    const number = Number(value || 0);
    return number > 0 ? `+${number}` : String(number);
  }

  function renderElementControls(force=false){
    const container = $('elementControlList');
    if(!container) return;
    if(!force && renderedElementLayout === layout){
      refreshElementControlAvailability();
      return;
    }

    renderedElementLayout = layout;
    const elements = activeLayoutConfig().elements || [];

    if(!elements.length){
      container.innerHTML = '<div class="hint-box">이 템플릿에는 이동 가능한 텍스트·메타 요소가 없습니다.</div>';
      return;
    }

    container.innerHTML = elements.map(elementKey => {
      const meta = ELEMENT_META[elementKey];
      const placement = ensureElementPlacement(layout, elementKey);
      return `
        <div class="element-card" data-element-card="${elementKey}">
          <div class="element-card-head">
            <div class="element-card-title"><span>${meta.label}</span><span class="element-card-badge">${meta.badge}</span></div>
            <button class="element-reset" type="button" data-element-reset="${elementKey}">초기화</button>
          </div>
          <div class="element-control-grid">
            <label class="element-control-item">
              <span class="element-control-label-row"><span>크기</span><output data-element-output="${elementKey}:scale">${elementControlValueText('scale', placement.scale)}</output></span>
              <input type="range" min="60" max="180" value="${placement.scale}" data-element-key="${elementKey}" data-element-prop="scale" />
            </label>
            <label class="element-control-item">
              <span class="element-control-label-row"><span>X 위치</span><output data-element-output="${elementKey}:x">${elementControlValueText('x', placement.x)}</output></span>
              <input type="range" min="-1600" max="1600" step="1" value="${placement.x}" data-element-key="${elementKey}" data-element-prop="x" />
            </label>
            <label class="element-control-item">
              <span class="element-control-label-row"><span>Y 위치</span><output data-element-output="${elementKey}:y">${elementControlValueText('y', placement.y)}</output></span>
              <input type="range" min="-2400" max="2400" step="1" value="${placement.y}" data-element-key="${elementKey}" data-element-prop="y" />
            </label>
            ${meta.lineHeight ? `<label class="element-control-item">
              <span class="element-control-label-row"><span>행간</span><output data-element-output="${elementKey}:lineHeight">${elementControlValueText('lineHeight', placement.lineHeight)}</output></span>
              <input type="range" min="70" max="200" value="${placement.lineHeight}" data-element-key="${elementKey}" data-element-prop="lineHeight" />
            </label>` : ''}
          </div>
        </div>`;
    }).join('');

    refreshElementControlAvailability();
  }

  function refreshElementControlAvailability(){
    document.querySelectorAll('[data-element-card]').forEach(card => {
      const meta = ELEMENT_META[card.dataset.elementCard];
      const setting = meta?.setting ? $(meta.setting) : null;
      card.classList.toggle('is-disabled', !!setting && !setting.checked);
    });
  }

  function resetCurrentElementLayout(){
    const elements = activeLayoutConfig().elements || [];
    elements.forEach(elementKey => {
      ensureElementPlacement(layout, elementKey);
      elementLayoutState[layout][elementKey] = defaultElementPlacement();
    });
    renderElementControls(true);
    syncDesignStateAfterChange();
    saveState();
    renderPreview();
  }


  function recoverEnabledElementPositionIfNeeded(settingId){
    const checkbox = $(settingId);
    const elementKey = DISPLAY_SETTING_ELEMENT_KEYS[settingId];
    if(!checkbox?.checked || !elementKey) return false;

    const placement = ensureElementPlacement(layout, elementKey);
    const state = getState();
    const measureCanvas = document.createElement('canvas');
    const measureContext = measureCanvas.getContext('2d');
    if(!measureContext) return false;

    const model = buildModel(state, measureContext);
    const safeX = Math.max(500, model.width * 0.92);
    const safeY = Math.max(500, model.height * 0.92);
    const outside = Math.abs(Number(placement.x || 0)) > safeX || Math.abs(Number(placement.y || 0)) > safeY;

    if(!outside) return false;

    placement.x = 0;
    placement.y = 0;
    renderedElementLayout = null;
    renderElementControls(true);
    $('statusText').textContent = '표시 요소 위치를 화면 안으로 복구했습니다.';
    return true;
  }

  function setDefaults(){
    Object.entries(defaultData).forEach(([k,v]) => { if($(k)) $(k).value = v; });
    $('frameColor').value = '#f3eee4';
    $('titleFont').value = "'Pretendard', sans-serif";
    $('bodyFont').value = "'Source Han Sans KR', 'Noto Sans KR', sans-serif";
    $('metaFont').value = "'Pretendard', sans-serif";
    $('textColorMode').value = 'auto';
    $('titleColor').value = '#171717';
    $('bodyColor').value = '#171717';
    $('metaColor').value = '#5f5f5f';
    $('locationColor').value = '#5f5f5f';
    $('posterTitleDirection').value = 'horizontal';
    $('posterBodyDirection').value = 'horizontal';
    $('posterTitleSize').value = '66';
    $('posterBodySize').value = '22';
    $('posterTitleX').value = '0';
    $('posterTitleY').value = '72';
    $('posterBodyX').value = '0';
    $('posterBodyY').value = '84';
    $('titleScale').value = '100';
    $('titleOffsetX').value = '0';
    $('titleOffsetY').value = '0';
    $('bodyScale').value = '100';
    $('bodyOffsetX').value = '0';
    $('bodyOffsetY').value = '0';
    $('locationScale').value = '100';
    $('locationOffsetX').value = '0';
    $('locationOffsetY').value = '0';
    $('exifScale').value = '100';
    $('exifOffsetX').value = '0';
    $('exifOffsetY').value = '0';
  }

  function getState(){
    const ids = [
      'make','model','lens','focal','aperture','shutter','iso','date','time',
      'title','location','project','rating','thought','note','promptText','creator','watermarkText',
      'theme','titleFont','bodyFont','metaFont','textColorMode','titleColor','bodyColor','metaColor','locationColor','posterTitleDirection','posterBodyDirection','posterTitleSize','posterBodySize','posterTitleX','posterTitleY','posterBodyX','posterBodyY','titleScale','titleOffsetX','titleOffsetY','bodyScale','bodyOffsetX','bodyOffsetY','locationScale','locationOffsetX','locationOffsetY','exifScale','exifOffsetX','exifOffsetY','frameColor','margin','radius','creatorFormat','creatorColor','watermarkColor'
    ];
    const state = { layout, batchApplyMode, elementLayoutState: JSON.parse(JSON.stringify(elementLayoutState)) };
    ids.forEach(id => state[id] = $(id).value);
    ['showTitle','showLocation','showThought','showNote','showProject','showRating','showPrompt','showLogo','showExif','showCreator','showWatermark']
      .forEach(id => state[id] = $(id).checked);
    state.watermarkDataUrl = virtualTextValues.watermarkDataUrl || '';
    state.watermarkFileName = virtualTextValues.watermarkFileName || '';
    return state;
  }

  function saveState(){
    try{ localStorage.setItem('framenote-v248-state', JSON.stringify(getState())); }catch(e){}
  }

  function restoreState(){
    try{
      const s = JSON.parse(localStorage.getItem('framenote-v248-state') || localStorage.getItem('framenote-v247-state') || localStorage.getItem('framenote-v246-state') || localStorage.getItem('framenote-v245-state') || localStorage.getItem('framenote-v241-state') || localStorage.getItem('framenote-v240-state') || localStorage.getItem('framenote-v239-state') || localStorage.getItem('framenote-v234-state') || localStorage.getItem('framenote-v233-state') || 'null');
      if(!s) return;
      Object.entries(s).forEach(([k,v]) => {
        if(k === 'layout'){ layout = v; return; }
        if(k === 'batchApplyMode'){ batchApplyMode = v !== false; return; }
        if(k === 'elementLayoutState'){ elementLayoutState = v && typeof v === 'object' ? v : {}; return; }
        const el = $(k); if(!el) return;
        if(el.type === 'checkbox') el.checked = !!v;
        else el.value = v;
      });
    }catch(e){}
  }

  function normalizeFontSelections(){
    const defaults = {
      titleFont: "'Pretendard', sans-serif",
      bodyFont: "'Source Han Sans KR', 'Noto Sans KR', sans-serif",
      metaFont: "'Pretendard', sans-serif"
    };
    Object.entries(defaults).forEach(([id, fallback]) => {
      const select = $(id);
      const exists = [...select.options].some(option => option.value === select.value);
      if(!exists) select.value = fallback;
    });
  }

  function waitForFonts(timeoutMs=3500){
    return Promise.race([
      document.fonts.ready,
      new Promise(resolve => setTimeout(resolve, timeoutMs))
    ]);
  }

  function layoutConfigFor(source=layout){
    const layoutName = typeof source === 'string'
      ? source
      : (source && source.layout ? source.layout : layout);
    return LAYOUT_CONFIG[layoutName] || LAYOUT_CONFIG.journal;
  }

  function activeLayoutConfig(){
    return layoutConfigFor(layout);
  }

  function isActiveSetting(state, name){
    return layoutConfigFor(state).settings.includes(name) && !!state[name];
  }

  function effectiveTheme(state){
    if(state.theme !== 'auto') return BRANDS[state.theme] || BRANDS.fujifilm;
    const text = `${state.make} ${state.model}`.toLowerCase();
    if(text.includes('fuji')) return BRANDS.fujifilm;
    if(text.includes('leica')) return BRANDS.leica;
    if(text.includes('canon')) return BRANDS.canon;
    if(text.includes('nikon')) return BRANDS.nikon;
    if(text.includes('sony')) return BRANDS.sony;
    if(text.includes('panasonic') || text.includes('lumix')) return BRANDS.lumix;
    if(text.includes('olympus') || text.includes('om system')) return BRANDS.om;
    if(text.includes('ricoh')) return BRANDS.ricoh;
    return BRANDS.fujifilm;
  }

  function stylesForLayout(lay){
    const frameColorInput = $('frameColor');
    const hint = $('styleConstraintHint');
    const disabled = (lay === 'contact' || lay === 'stamp');
    frameColorInput.disabled = disabled;

    if(lay === 'contact'){
      hint.textContent = 'Contact Sheet C는 필름 시트 스타일로 고정되어 프레임 색상 수정이 비활성화됩니다.';
    } else if(lay === 'stamp'){
      hint.textContent = 'Film Date Overlay는 프레임 없는 사진 위 오버레이이므로 프레임 색상 수정이 비활성화됩니다.';
    } else if(lay === 'poster'){
      hint.textContent = 'Poster Overlay는 사진 위 텍스트 중심 레이아웃입니다.';
    } else if(lay === 'frameonly'){
      hint.textContent = 'Clean Frame은 사진과 프레임만 표시합니다.';
    } else if(lay === 'minimal'){
      hint.textContent = 'Minimal Bottom Bar는 사진 아래 얇은 정보 바를 사용합니다.';
    } else if(lay === 'caption'){
      hint.textContent = 'Exhibition Caption은 사진 아래에 전시 캡션 형식의 설명을 배치합니다.';
    } else if(lay === 'polaroid'){
      hint.textContent = 'Polaroid Note는 넓은 하단 여백에 제목과 메모를 배치합니다.';
    } else {
      hint.textContent = '현재 레이아웃은 프레임 색상 수정 가능.';
    }
  }

  function updateTextColorControls(){
    const cfg = activeLayoutConfig();
    const supportedColors = cfg.colors || [];
    const hasEditableColors = supportedColors.length > 0;
    const custom = $('textColorMode').value === 'custom';

    const modeLabel = document.querySelector('[data-color-mode]');
    if(modeLabel){
      modeLabel.classList.toggle('hidden-control', !hasEditableColors);
    }
    $('textColorMode').disabled = !hasEditableColors;

    document.querySelectorAll('[data-color-control]').forEach(label => {
      const colorType = label.dataset.colorControl;
      const supported = supportedColors.includes(colorType);
      label.classList.toggle('hidden-control', !supported);
      label.classList.toggle('color-control-disabled', supported && !custom);

      const input = label.querySelector('input');
      if(input){
        input.disabled = !supported || !custom;
      }
    });
  }

  function updateControlVisibility(){
    const cfg = activeLayoutConfig();
    const displayOptions = $('displayOptions');
    if(displayOptions) displayOptions.style.display = 'grid';

    document.querySelectorAll('[data-setting]').forEach(el => {
      el.classList.toggle('hidden-control', !cfg.settings.includes(el.dataset.setting));
    });

    document.querySelectorAll('[data-text]').forEach(el => {
      el.classList.toggle('hidden-control', !cfg.texts.includes(el.dataset.text));
    });

    $('brandToggleText').textContent = layout === 'stamp' ? '브랜드명' : '브랜드 로고';

    document.querySelectorAll('[data-poster-control]').forEach(el => {
      el.classList.toggle('hidden-control', layout !== 'poster');
    });

    renderElementControls();
    updateTextColorControls();
  }

  function photoRatio(){
    if(imageLoaded && image.naturalWidth && image.naturalHeight) return image.naturalWidth / image.naturalHeight;
    return 3/2;
  }

  const EXIF_FIELD_IDS = ['make','model','lens','focal','aperture','shutter','iso','date','time'];
  const EXIF_FIELD_SET = new Set(EXIF_FIELD_IDS);


function clonePlain(value){
  return JSON.parse(JSON.stringify(value));
}

function captureDesignState(){
  const state = {
    layout,
    elementLayoutState: clonePlain(elementLayoutState)
  };
  DESIGN_VALUE_FIELD_IDS.forEach(id => {
    const element = $(id);
    state[id] = element ? element.value : '';
  });
  DESIGN_CHECK_FIELD_IDS.forEach(id => {
    const element = $(id);
    state[id] = !!element?.checked;
  });
  return state;
}

function applyDesignState(design, {render=false, save=false} = {}){
  if(!design) return;
  layout = design.layout || 'journal';
  elementLayoutState = clonePlain(design.elementLayoutState || {});

  DESIGN_VALUE_FIELD_IDS.forEach(id => {
    const element = $(id);
    if(element && design[id] != null) element.value = design[id];
  });
  DESIGN_CHECK_FIELD_IDS.forEach(id => {
    const element = $(id);
    if(element && design[id] != null) element.checked = !!design[id];
  });

  normalizeFontSelections();
  document.querySelectorAll('.template').forEach(button => {
    button.classList.toggle('active', button.dataset.layout === layout);
  });
  stylesForLayout(layout);
  renderedElementLayout = null;
  updateControlVisibility();
  renderElementControls(true);
  if(save) saveState();
  if(render) renderPreview();
}

function syncDesignStateAfterChange({refreshList=false} = {}){
  const design = captureDesignState();
  if(batchApplyMode){
    photoItems.forEach(item => { item.designState = clonePlain(design); });
  }else{
    const item = getSelectedPhotoItem();
    if(item) item.designState = clonePlain(design);
  }
  if(refreshList) renderBatchList();
}

function updateBatchModeUI(){
  const toggle = $('batchApplyToggle');
  const panel = $('batchModePanel');
  const title = $('batchModeTitle');
  const description = $('batchModeDescription');
  if(toggle) toggle.checked = batchApplyMode;
  if(panel) panel.classList.toggle('individual', !batchApplyMode);
  if(title) title.textContent = batchApplyMode ? '일괄 적용 모드' : '개별 작업 모드';
  if(description){
    description.textContent = batchApplyMode
      ? '템플릿·스타일·표시 요소·요소 배치를 모든 사진에 동일하게 적용합니다.'
      : '선택한 사진에만 템플릿과 스타일을 저장합니다. 사진을 전환하면 각 설정이 복원됩니다.';
  }
}

async function setBatchApplyMode(enabled){
  syncCurrentPhotoValues();
  const currentDesign = captureDesignState();
  batchApplyMode = !!enabled;

  // 모드를 전환하는 시점의 현재 디자인을 모든 사진의 시작점으로 맞춘다.
  // 이후 일괄 모드에서는 계속 함께 변경되고, 개별 모드에서는 사진별로 분리된다.
  photoItems.forEach(item => { item.designState = clonePlain(currentDesign); });

  updateBatchModeUI();
  renderBatchList();
  saveState();
  $('statusText').textContent = batchApplyMode ? '일괄 적용 모드' : '개별 작업 모드';
}

const virtualTextValues = {watermarkDataUrl:'', watermarkFileName:''};

function captureTextValues(){
  const values = {};
  TEXT_FIELD_IDS.forEach(id => {
    const element = $(id);
    values[id] = element ? element.value : (virtualTextValues[id] || '');
  });
  return values;
}

function setTextValues(values, {render=true, save=true} = {}){
  TEXT_FIELD_IDS.forEach(id => {
    const element = $(id);
    if(element) element.value = values && values[id] != null ? values[id] : ''; else virtualTextValues[id] = values && values[id] != null ? values[id] : '';
  });
  const watermarkLabel = $('watermarkFileName');
  if(watermarkLabel) watermarkLabel.textContent = virtualTextValues.watermarkFileName ? `불러온 워터마크: ${virtualTextValues.watermarkFileName}` : '불러온 워터마크 없음';
  if(save) saveState();
  if(render) renderPreview();
}

function capturePhotoFieldValues(){
  return {
    textValues: captureTextValues(),
    exifValues: captureExifValues()
  };
}

function applyPhotoFieldValues(payload, {render=true, save=true} = {}){
  setTextValues(payload && payload.textValues ? payload.textValues : {}, {render:false, save:false});
  setExifValues(payload && payload.exifValues ? payload.exifValues : {}, {render:false, save:false});
  if(save) saveState();
  if(render) renderPreview();
}

function getSelectedPhotoItem(){
  return photoItems.find(item => item.id === selectedPhotoId) || null;
}

function syncCurrentPhotoValues(){
  const item = getSelectedPhotoItem();
  if(!item) return;
  item.textValues = captureTextValues();
  item.exifValues = captureExifValues();
  if(!batchApplyMode){
    item.designState = clonePlain(captureDesignState());
  }
}

function renderBatchList(){
  const list = $('batchList');
  const countEl = $('batchCount');
  if(countEl) countEl.textContent = `${photoItems.length}장`;
  if(!list) return;

  if(!photoItems.length){
    list.innerHTML = '<div class="batch-note">아직 불러온 사진이 없습니다.</div>';
    return;
  }

  list.innerHTML = photoItems.map((item, index) => {
    const sizeText = item.width && item.height ? `${item.width} × ${item.height}` : '해상도 읽는 중…';
    const exifBadge = item.hasExif ? 'EXIF' : 'NO EXIF';
    const active = item.id === selectedPhotoId ? ' active' : '';
    const safeName = escapeHtml(item.name || `photo_${index+1}`);
    const itemLayout = batchApplyMode ? layout : (item.designState?.layout || layout);
    const layoutLabel = LAYOUT_LABELS[itemLayout] || itemLayout;
    const modeLabel = batchApplyMode ? '일괄' : '개별';
    return `<button class="batch-item${active}" type="button" data-photo-id="${item.id}">
      <span class="batch-item-name">${index + 1}. ${safeName}</span>
      <span class="batch-item-meta"><span>${sizeText}</span><span>${item.typeLabel || ''}</span><span>${exifBadge}</span></span>
      <span class="batch-item-mode">${modeLabel} · ${layoutLabel}</span>
    </button>`;
  }).join('');
}

function escapeHtml(text){
  return String(text ?? '').replace(/[&<>"']/g, ch => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[ch]));
}

async function loadPreviewImageFromItem(item){
  if(!item) return;
  return new Promise((resolve, reject) => {
    const nextImage = new Image();
    nextImage.onload = () => {
      image = nextImage;
      imageLoaded = true;
      currentFileName = item.name || 'image.jpg';
      $('thumb').src = item.url;
      $('fileName').textContent = currentFileName;
      $('imageSize').textContent = `${item.width || nextImage.naturalWidth} × ${item.height || nextImage.naturalHeight}`;
      originalExifValues = item.originalExifValues || null;
      updateExifSummary();
      renderPreview();
      $('statusText').textContent = '준비됨';
      resolve();
    };
    nextImage.onerror = () => reject(new Error('이미지를 불러오지 못했습니다.'));
    nextImage.src = item.url;
  });
}

async function selectPhotoById(id, {preserveCurrent=true} = {}){
  const nextItem = photoItems.find(item => item.id === id);
  if(!nextItem) return;
  if(preserveCurrent) syncCurrentPhotoValues();
  selectedPhotoId = id;

  if(!batchApplyMode){
    if(!nextItem.designState) nextItem.designState = clonePlain(captureDesignState());
    applyDesignState(nextItem.designState, {render:false, save:false});
    await ensureSelectedUserFonts({render:false, silent:true});
  }

  applyPhotoFieldValues({textValues: nextItem.textValues, exifValues: nextItem.exifValues}, {render:false, save:false});
  await loadPreviewImageFromItem(nextItem);
  renderBatchList();
}

function buildStateForPhoto(baseState, item){
  let state = clonePlain(baseState);
  if(!batchApplyMode && item.designState){
    const design = clonePlain(item.designState);
    Object.assign(state, design);
    state.layout = design.layout || state.layout;
    state.elementLayoutState = clonePlain(design.elementLayoutState || {});
  }
  Object.assign(state, item.textValues || {}, item.exifValues || {});
  return state;
}

async function measureImageSource(url){
  return new Promise((resolve, reject) => {
    const probe = new Image();
    probe.onload = () => resolve({width: probe.naturalWidth, height: probe.naturalHeight});
    probe.onerror = () => reject(new Error('이미지 크기를 읽지 못했습니다.'));
    probe.src = url;
  });
}

async function createPhotoItemFromFile(file, baseTextValues, baseDesignState){
  const url = URL.createObjectURL(file);
  const dims = await measureImageSource(url);
  let parsedExif = {};
  if(file.type === 'image/jpeg'){
    try{
      parsedExif = parseExif(await file.arrayBuffer()) || {};
    }catch(error){
      console.warn('EXIF parse failed:', error);
    }
  }

  const exifValues = {};
  EXIF_FIELD_IDS.forEach(id => exifValues[id] = '');
  const previousImage = image;
  const previousLoaded = imageLoaded;
  const backupValues = captureExifValues();
  const blanks = {};
  EXIF_FIELD_IDS.forEach(id => blanks[id] = '');
  setExifValues(blanks, {render:false, save:false});
  applyExif(parsedExif);
  const captured = captureExifValues();
  Object.assign(exifValues, captured);
  setExifValues(backupValues, {render:false, save:false});
  image = previousImage;
  imageLoaded = previousLoaded;

  return {
    id: `photo_${++photoIdSeed}`,
    name: file.name,
    url,
    file,
    width: dims.width,
    height: dims.height,
    hasExif: !!Object.values(parsedExif || {}).filter(Boolean).length,
    originalExifValues: exifValues,
    exifValues: {...exifValues},
    textValues: {...baseTextValues},
    designState: clonePlain(baseDesignState),
    typeLabel: (file.type || '').replace('image/','').toUpperCase() || 'IMAGE'
  };
}

async function createPhotoItemFromUrl(name, url, baseTextValues, baseDesignState){
  const dims = await measureImageSource(url);
  return {
    id: `photo_${++photoIdSeed}`,
    name,
    url,
    file: null,
    width: dims.width,
    height: dims.height,
    hasExif: false,
    originalExifValues: null,
    exifValues: (() => { const blank = {}; EXIF_FIELD_IDS.forEach(id => blank[id] = ''); return blank; })(),
    textValues: {...baseTextValues},
    designState: clonePlain(baseDesignState),
    typeLabel: 'SAMPLE'
  };
}

async function loadFiles(fileList){
  const files = [...fileList].filter(file => /^image\//.test(file.type));
  if(!files.length) return;
  $('statusText').textContent = `사진 ${files.length}장 읽는 중…`;
  const baseTextValues = captureTextValues();
  const baseDesignState = captureDesignState();
  const items = [];
  for(const file of files){
    items.push(await createPhotoItemFromFile(file, baseTextValues, baseDesignState));
  }
  photoItems = items;
  renderBatchList();
  await selectPhotoById(photoItems[0].id, {preserveCurrent:false});
  $('statusText').textContent = `사진 ${photoItems.length}장 준비됨`;
}

function captureExifValues(){
    const values = {};
    EXIF_FIELD_IDS.forEach(id => {
      const element = $(id);
      values[id] = element ? element.value : '';
    });
    return values;
  }

  function setExifValues(values, {render=true, save=true} = {}){
    EXIF_FIELD_IDS.forEach(id => {
      const element = $(id);
      if(element) element.value = values && values[id] != null ? values[id] : '';
    });
    updateExifSummary();
    if(save) saveState();
    if(render) renderPreview();
  }

  function updateExifSummary(){
    const values = captureExifValues();
    const camera = [values.make, values.model].filter(Boolean).join(' · ');
    const exposure = [values.focal, values.aperture, values.shutter, values.iso].filter(Boolean).join('  ·  ');
    const dateTime = [values.date ? values.date.replaceAll('-', '.') : '', values.time].filter(Boolean).join('  ');

    const cameraEl = $('exifSummaryCamera');
    const lensEl = $('exifSummaryLens');
    const exposureEl = $('exifSummaryExposure');
    const dateEl = $('exifSummaryDate');

    if(cameraEl) cameraEl.textContent = camera || '카메라 정보 없음';
    if(lensEl) lensEl.textContent = values.lens || '렌즈 정보 없음';
    if(exposureEl) exposureEl.textContent = exposure || '노출 정보 없음';
    if(dateEl) dateEl.textContent = dateTime;
  }

  function restoreOriginalExif(){
    if(!originalExifValues){
      alert('현재 사진에서 읽어 둔 EXIF 정보가 없습니다.');
      return;
    }
    setExifValues(originalExifValues);
    $('statusText').textContent = '사진 EXIF 복원 완료';
  }

  function clearExifValues(){
    const confirmed = window.confirm('현재 입력된 EXIF 정보를 모두 비울까요?');
    if(!confirmed) return;
    const cleared = {};
    EXIF_FIELD_IDS.forEach(id => { cleared[id] = ''; });
    setExifValues(cleared);
    $('statusText').textContent = 'EXIF 정보 비움';
  }

  function dateText(state){
    return state.date ? state.date.replaceAll('-', '.') : '';
  }

  function exifLine(state){
    return [state.focal, state.aperture, state.shutter, state.iso].filter(Boolean).join('  ·  ');
  }

  function stampExifLine(state){
    return [state.focal, state.aperture, state.shutter, state.iso].filter(Boolean).join(' ').toUpperCase().replace(/MM/g,'MM');
  }

  function roundedRectPath(ctx, x,y,w,h,r){
    r = Math.min(r,w/2,h/2);
    ctx.beginPath();
    ctx.moveTo(x+r,y);
    ctx.arcTo(x+w,y,x+w,y+h,r);
    ctx.arcTo(x+w,y+h,x,y+h,r);
    ctx.arcTo(x,y+h,x,y,r);
    ctx.arcTo(x,y,x+w,y,r);
    ctx.closePath();
  }

  function drawPhoto(ctx, x, y, w, h, radius){
    ctx.save();
    roundedRectPath(ctx, x, y, w, h, radius);
    ctx.clip();
    if(imageLoaded){
      ctx.drawImage(image, x, y, w, h);
    }else{
      ctx.fillStyle = '#b7b7b7';
      ctx.fillRect(x,y,w,h);
    }
    ctx.restore();
  }

  function setFont(ctx, size, weight, family, italic=false){
    ctx.font = `${italic ? 'italic ' : ''}${weight} ${size}px ${family}`;
  }

  function drawText(ctx, str, x, y, size=28, color='#111', weight='400', family='Arial', align='left', italic=false){
    ctx.save();
    ctx.fillStyle = color;
    ctx.textAlign = align;
    ctx.textBaseline = 'alphabetic';
    setFont(ctx, size, weight, family, italic);
    ctx.fillText(String(str || ''), x, y);
    ctx.restore();
  }

  function drawFittedText(ctx, str, x, y, maxWidth, size, minSize, color='#111', weight='400', family='Arial', align='left'){
    const value = String(str || '');
    let finalSize = size;

    ctx.save();
    ctx.textBaseline = 'alphabetic';
    ctx.textAlign = align;
    ctx.fillStyle = color;

    setFont(ctx, finalSize, weight, family);
    while(finalSize > minSize && ctx.measureText(value).width > maxWidth){
      finalSize -= 0.5;
      setFont(ctx, finalSize, weight, family);
    }

    let output = value;
    if(ctx.measureText(output).width > maxWidth){
      const ellipsis = '…';
      while(output.length > 1 && ctx.measureText(output + ellipsis).width > maxWidth){
        output = output.slice(0, -1);
      }
      output += ellipsis;
    }

    const clipX = align === 'right' ? x - maxWidth : x;
    ctx.beginPath();
    ctx.rect(clipX, y - finalSize * 1.15, maxWidth, finalSize * 1.45);
    ctx.clip();
    ctx.fillText(output, x, y);
    ctx.restore();

    return finalSize;
  }

  function wrapLines(ctx, str, maxWidth, size, family, weight='400', maxLines=6){
    setFont(ctx, size, weight, family);
    const lines = [];
    const paras = String(str || '').split('\n');
    paras.forEach((para, pIdx) => {
      const text = para || '';
      if(text.trim() === ''){
        if(lines.length < maxLines) lines.push('');
        return;
      }
      let line = '';
      for(const ch of text){
        const test = line + ch;
        if(ctx.measureText(test).width > maxWidth && line){
          lines.push(line);
          line = ch;
          if(lines.length >= maxLines) break;
        }else{
          line = test;
        }
      }
      if(lines.length < maxLines && line) lines.push(line);
      // Explicit newline already starts the next paragraph on the next line.
    });
    return lines.slice(0, maxLines);
  }

  function drawWrappedText(ctx, str, x, y, maxWidth, lineHeight, size, color, family, weight='400', maxLines=6, align='left'){
    ctx.save();
    ctx.fillStyle = color;
    ctx.textAlign = align;
    ctx.textBaseline = 'top';
    setFont(ctx, size, weight, family);
    const lines = wrapLines(ctx, str, maxWidth, size, family, weight, maxLines);
    lines.forEach((line, i) => ctx.fillText(line, x, y + i * lineHeight));
    ctx.restore();
    return lines.length * lineHeight;
  }

  function wrapLinesComplete(ctx, str, maxWidth, size, family, weight='400'){
    setFont(ctx, size, weight, family);
    const lines = [];
    const paragraphs = String(str || '').split('\n');

    paragraphs.forEach((paragraph, paragraphIndex) => {
      if(paragraph === ''){
        lines.push('');
        return;
      }

      let lineText = '';
      for(const character of paragraph){
        const test = lineText + character;
        if(lineText && ctx.measureText(test).width > maxWidth){
          lines.push(lineText);
          lineText = character;
        }else{
          lineText = test;
        }
      }

      if(lineText) lines.push(lineText);
      // Explicit newline already creates the next line without an extra blank row.
    });

    return lines;
  }

  function fitWrappedText(ctx, str, maxWidth, maxLines, startSize, minSize, family, weight='700'){
    let size = startSize;
    let completeLines = [];

    while(size >= minSize){
      completeLines = wrapLinesComplete(ctx, str, maxWidth, size, family, weight);
      if(completeLines.length <= maxLines) break;
      size -= 2;
    }

    size = Math.max(minSize, size);
    completeLines = wrapLinesComplete(ctx, str, maxWidth, size, family, weight);

    const clipped = completeLines.length > maxLines;
    const lines = completeLines.slice(0, maxLines);

    if(clipped && lines.length){
      setFont(ctx, size, weight, family);
      const ellipsis = '…';
      let last = lines[lines.length - 1];

      while(last.length > 1 && ctx.measureText(last + ellipsis).width > maxWidth){
        last = last.slice(0, -1);
      }
      lines[lines.length - 1] = last + ellipsis;
    }

    return {
      size,
      lineHeight: Math.round(size * 1.08),
      lines
    };
  }

  function drawFittedWrappedText(ctx, str, x, y, maxWidth, maxLines, startSize, minSize, color, family, weight='700', align='left'){
    const fitted = fitWrappedText(
      ctx,
      str,
      maxWidth,
      maxLines,
      startSize,
      minSize,
      family,
      weight
    );

    ctx.save();
    ctx.fillStyle = color;
    ctx.textAlign = align;
    ctx.textBaseline = 'top';
    setFont(ctx, fitted.size, weight, family);

    fitted.lines.forEach((lineText, index) => {
      ctx.fillText(lineText, x, y + index * fitted.lineHeight);
    });

    ctx.restore();

    return {
      ...fitted,
      height: fitted.lines.length * fitted.lineHeight
    };
  }

  function line(ctx, x1,y1,x2,y2,color='#bbb',width=1){
    ctx.save();
    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    ctx.beginPath();
    ctx.moveTo(x1,y1);
    ctx.lineTo(x2,y2);
    ctx.stroke();
    ctx.restore();
  }

  function fillGradientRect(ctx, x, y, w, h, direction='vertical', stops=[]){
    const grad = direction === 'horizontal'
      ? ctx.createLinearGradient(x, y, x + w, y)
      : ctx.createLinearGradient(x, y, x, y + h);
    stops.forEach(([offset, color]) => grad.addColorStop(offset, color));
    ctx.save();
    ctx.fillStyle = grad;
    ctx.fillRect(x, y, w, h);
    ctx.restore();
  }

  function hexToRgb(hex){
    const normalized = String(hex || '').trim();
    const match = normalized.match(/^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i);
    if(!match) return null;
    return {
      r: parseInt(match[1], 16),
      g: parseInt(match[2], 16),
      b: parseInt(match[3], 16)
    };
  }

  function frameShadowStrength(frameColor){
    const rgb = hexToRgb(frameColor);
    if(!rgb) return 0.06;
    const luminance = (0.2126 * rgb.r + 0.7152 * rgb.g + 0.0722 * rgb.b) / 255;
    if(luminance > 0.92) return 0.13;
    if(luminance > 0.82) return 0.10;
    if(luminance > 0.68) return 0.07;
    return 0.0;
  }

  function drawFrameEdgeShadow(ctx, x, y, w, h, frameColor){
    let alpha = frameShadowStrength(frameColor);
    if(alpha <= 0) return;

    /*
      A real shadow outside the JPEG canvas would require adding extra outer
      pixels. Instead, create a clearly visible but soft inset halo along the
      exact frame boundary. Concentric full-frame outlines keep all four sides
      and all four corners continuous, so no rectangular corner blocks appear.
    */
    alpha = Math.min(0.22, alpha * 1.42);
    const depth = Math.max(12, Math.min(24, Math.round(Math.min(w, h) * 0.024)));

    ctx.save();
    ctx.lineJoin = 'miter';
    ctx.lineCap = 'butt';

    for(let i = 0; i < depth; i++){
      const inset = i + 0.5;
      const progress = i / Math.max(1, depth - 1);
      const opacity = alpha * Math.pow(1 - progress, 2.15);
      const sw = w - inset * 2;
      const sh = h - inset * 2;
      if(sw <= 0 || sh <= 0) break;

      ctx.strokeStyle = `rgba(0,0,0,${opacity})`;
      ctx.lineWidth = 1;
      ctx.strokeRect(x + inset, y + inset, sw, sh);
    }

    /* A thin boundary line anchors very light frames on white pages. */
    ctx.strokeStyle = `rgba(0,0,0,${Math.min(0.16, alpha * 0.72)})`;
    ctx.lineWidth = 1;
    ctx.strokeRect(x + 0.5, y + 0.5, Math.max(1, w - 1), Math.max(1, h - 1));
    ctx.restore();
  }

  function drawFrameSurface(ctx, x, y, w, h, color){
    ctx.fillStyle = color;
    ctx.fillRect(x, y, w, h);
    drawFrameEdgeShadow(ctx, x, y, w, h, color);
  }

  function getTextAdjustments(state, kind, fallbackColor){
    const scaleRaw = Number(state[`${kind}Scale`] || 100);
    const dx = Number(state[`${kind}OffsetX`] || 0);
    const dy = Number(state[`${kind}OffsetY`] || 0);
    const scale = Math.max(0.6, Math.min(1.8, scaleRaw / 100));
    const color = state.textColorMode === 'custom'
      ? (state[`${kind}Color`] || fallbackColor)
      : fallbackColor;
    return {scale, dx, dy, color};
  }

  function getElementAdjustments(state, kind, elementKey, fallbackColor){
    const base = getTextAdjustments(state, kind, fallbackColor);
    const element = elementPlacementFromState(state, elementKey || kind);
    const elementScale = Math.max(0.6, Math.min(1.8, Number(element.scale || 100) / 100));
    return {
      scale:base.scale * elementScale,
      dx:base.dx + Number(element.x || 0),
      dy:base.dy + Number(element.y || 0),
      lineHeightScale:Math.max(0.7, Math.min(2.0, Number(element.lineHeight || 100) / 100)),
      color:base.color
    };
  }

  function applyInputTextShadow(ctx){
    ctx.shadowColor = 'rgba(0,0,0,0.16)';
    ctx.shadowBlur = 2;
    ctx.shadowOffsetX = 1;
    ctx.shadowOffsetY = 1;
  }

  function drawManagedText(ctx, state, kind, str, x, y, size=28, color='#111', weight='400', family='Arial', align='left', italic=false, elementKey=kind){
    const adj = getElementAdjustments(state, kind, elementKey, color);
    ctx.save();
    ctx.fillStyle = adj.color;
    ctx.textAlign = align;
    ctx.textBaseline = 'alphabetic';
    applyInputTextShadow(ctx);
    setFont(ctx, size * adj.scale, weight, family, italic);
    ctx.fillText(String(str || ''), x + adj.dx, y + adj.dy);
    ctx.restore();
  }

  function drawManagedFittedText(ctx, state, kind, str, x, y, maxWidth, size, minSize, color='#111', weight='400', family='Arial', align='left', elementKey=kind){
    const value = String(str || '');
    const adj = getElementAdjustments(state, kind, elementKey, color);
    let finalSize = size * adj.scale;
    const finalMin = Math.max(8, minSize * Math.min(adj.scale, 1.35));
    const drawX = x + adj.dx;
    const drawY = y + adj.dy;

    ctx.save();
    ctx.textBaseline = 'alphabetic';
    ctx.textAlign = align;
    ctx.fillStyle = adj.color;
    applyInputTextShadow(ctx);

    setFont(ctx, finalSize, weight, family);
    while(finalSize > finalMin && ctx.measureText(value).width > maxWidth){
      finalSize -= 0.5;
      setFont(ctx, finalSize, weight, family);
    }

    let output = value;
    if(ctx.measureText(output).width > maxWidth){
      const ellipsis = '…';
      while(output.length > 1 && ctx.measureText(output + ellipsis).width > maxWidth){
        output = output.slice(0, -1);
      }
      output += ellipsis;
    }

    const clipX = align === 'right' ? drawX - maxWidth : drawX;
    ctx.beginPath();
    ctx.rect(clipX, drawY - finalSize * 1.15, maxWidth, finalSize * 1.45);
    ctx.clip();
    ctx.fillText(output, drawX, drawY);
    ctx.restore();

    return finalSize;
  }

  function drawManagedWrappedText(ctx, state, kind, str, x, y, maxWidth, lineHeight, size, color, family, weight='400', maxLines=6, align='left', elementKey=kind){
    const adj = getElementAdjustments(state, kind, elementKey, color);
    const scaledSize = size * adj.scale;
    const scaledLineHeight = lineHeight * adj.scale * adj.lineHeightScale;
    ctx.save();
    ctx.fillStyle = adj.color;
    ctx.textAlign = align;
    ctx.textBaseline = 'top';
    applyInputTextShadow(ctx);
    setFont(ctx, scaledSize, weight, family);
    const lines = wrapLines(ctx, str, maxWidth, scaledSize, family, weight, maxLines);
    lines.forEach((line, i) => ctx.fillText(line, x + adj.dx, y + adj.dy + i * scaledLineHeight));
    ctx.restore();
    return lines.length * scaledLineHeight;
  }

  function drawManagedFittedWrappedText(ctx, state, kind, str, x, y, maxWidth, maxLines, startSize, minSize, color, family, weight='700', align='left', elementKey=kind){
    const adj = getElementAdjustments(state, kind, elementKey, color);
    const fitted = fitWrappedText(ctx, str, maxWidth, maxLines, startSize * adj.scale, Math.max(8, minSize * Math.min(adj.scale, 1.35)), family, weight);
    ctx.save();
    ctx.fillStyle = adj.color;
    ctx.textAlign = align;
    ctx.textBaseline = 'top';
    applyInputTextShadow(ctx);
    setFont(ctx, fitted.size, weight, family);
    const managedLineHeight = fitted.lineHeight * adj.lineHeightScale;
    fitted.lines.forEach((lineText, index) => {
      ctx.fillText(lineText, x + adj.dx, y + adj.dy + index * managedLineHeight);
    });
    ctx.restore();
    return {
      ...fitted,
      lineHeight:managedLineHeight,
      height: fitted.lines.length * managedLineHeight,
      x: x + adj.dx,
      y: y + adj.dy
    };
  }


  const watermarkImageCache = new Map();

  function creatorDisplayText(state){
    const name = String(state.creator || '').trim();
    if(!name) return '';
    const format = state.creatorFormat || 'copyright';
    const year = String(state.date || '').slice(0,4) || String(new Date().getFullYear());
    if(format === 'photoBy') return `Photo by ${name}`;
    if(format === 'copyrightYear') return `Copyright © ${year} ${name}`;
    if(format === 'nameOnly') return name;
    return `© ${name}`;
  }

  function getWatermarkImage(dataUrl){
    if(!dataUrl) return null;
    if(watermarkImageCache.has(dataUrl)) return watermarkImageCache.get(dataUrl);
    const record = {image:new Image(), loaded:false, failed:false};
    record.image.onload = () => { record.loaded = true; renderPreview(); };
    record.image.onerror = () => { record.failed = true; };
    record.image.src = dataUrl;
    watermarkImageCache.set(dataUrl, record);
    return record;
  }

  function drawTintedWatermarkImage(ctx, imageObject, x, y, width, height, color){
    const temp = document.createElement('canvas');
    temp.width = Math.max(1, Math.round(width));
    temp.height = Math.max(1, Math.round(height));
    const tctx = temp.getContext('2d');
    if(!tctx) return;
    tctx.drawImage(imageObject, 0, 0, temp.width, temp.height);
    tctx.globalCompositeOperation = 'source-in';
    tctx.fillStyle = color || '#ffffff';
    tctx.fillRect(0,0,temp.width,temp.height);
    ctx.drawImage(temp, x, y, width, height);
  }

  function drawUniversalOverlays(ctx, state, model){
    const metaFont = state.metaFont || "'Pretendard', sans-serif";
    if(isActiveSetting(state,'showCreator')){
      const text = creatorDisplayText(state);
      if(text){
        const adj = getElementAdjustments(state, 'meta', 'creator', state.creatorColor || '#ffffff');
        const size = 18 * adj.scale;
        ctx.save();
        ctx.textAlign = 'right';
        ctx.textBaseline = 'alphabetic';
        ctx.fillStyle = state.creatorColor || adj.color;
        applyInputTextShadow(ctx);
        setFont(ctx, size, '600', metaFont);
        ctx.fillText(text, model.width - 34 + adj.dx, model.height - 28 + adj.dy);
        ctx.restore();
      }
    }
    if(isActiveSetting(state,'showWatermark')){
      const adj = getElementAdjustments(state, 'meta', 'watermark', state.watermarkColor || '#ffffff');
      const dataUrl = state.watermarkDataUrl || '';
      const record = getWatermarkImage(dataUrl);
      if(record && record.loaded && !record.failed){
        const sourceW = record.image.naturalWidth || 1;
        const sourceH = record.image.naturalHeight || 1;
        const targetW = Math.min(model.width * 0.28, 260) * adj.scale;
        const targetH = targetW * sourceH / sourceW;
        const x = 34 + adj.dx;
        const y = model.height - targetH - 34 + adj.dy;
        ctx.save();
        applyInputTextShadow(ctx);
        drawTintedWatermarkImage(ctx, record.image, x, y, targetW, targetH, state.watermarkColor || '#ffffff');
        ctx.restore();
      }else if(state.watermarkText){
        const size = 18 * adj.scale;
        ctx.save();
        ctx.textAlign = 'left';
        ctx.textBaseline = 'alphabetic';
        ctx.fillStyle = state.watermarkColor || '#ffffff';
        applyInputTextShadow(ctx);
        setFont(ctx, size, '600', metaFont);
        ctx.fillText(String(state.watermarkText), 34 + adj.dx, model.height - 28 + adj.dy);
        ctx.restore();
      }
    }
  }

  function stars(ctx, x, y, n, color, size, family, align='left'){
    ctx.save();
    setFont(ctx, size, '700', family);
    ctx.textBaseline = 'alphabetic';

    const filledWidth = ctx.measureText('★').width;
    const emptyWidth = ctx.measureText('☆').width;
    const step = Math.max(filledWidth, emptyWidth) + size * 0.16;
    const totalWidth = step * 4 + Math.max(filledWidth, emptyWidth);
    let cursor = align === 'right' ? x - totalWidth : x;

    for(let i=0;i<5;i++){
      const filled = i < n;
      ctx.fillStyle = filled ? color : '#b7b7b7';
      const glyph = filled ? '★' : '☆';
      ctx.fillText(glyph, cursor, y);
      cursor += step;
    }
    ctx.restore();
    return totalWidth;
  }

  function logoPaths(key){
    return ['svg','png','jpg','jpeg','webp'].map(ext => `assets/logos/${key}.${ext}`);
  }

  function requestLocalLogo(theme){
    if(!theme || !theme.key) return null;
    if(logoCache.has(theme.key)) return logoCache.get(theme.key);

    const img = new Image();
    const record = {
      img,
      loaded:false,
      failed:false,
      embedded:false
    };

    logoCache.set(theme.key, record);

    img.onload = () => {
      record.loaded = true;
      renderPreview();
    };

    img.onerror = () => {
      record.failed = true;
      renderPreview();
    };

    const embeddedSource = EMBEDDED_LOGOS[theme.key];

    if(embeddedSource){
      record.embedded = true;
      img.src = embeddedSource;
      return record;
    }

    /*
      Fallback retained only for future logos not embedded in this build.
      Supplied brand logos never use this path.
    */
    const paths = logoPaths(theme.key);
    let index = 0;

    const tryNext = () => {
      if(index >= paths.length){
        record.failed = true;
        renderPreview();
        return;
      }

      img.onload = () => {
        record.loaded = true;
        renderPreview();
      };

      img.onerror = () => {
        index += 1;
        tryNext();
      };

      img.src = paths[index];
    };

    tryNext();
    return record;
  }

  function preloadEmbeddedLogos(){
    Object.keys(EMBEDDED_LOGOS).forEach(key => {
      const theme = Object.values(BRANDS).find(item => item.key === key);
      if(theme) requestLocalLogo(theme);
    });
  }

  function drawBrand(ctx, theme, state, x, y, maxW, maxH, family, align='left', fallbackColor=null, elementKey='logo'){
    if(!isActiveSetting(state, 'showLogo')){
      return {w:0, h:0, visible:false};
    }

    const logoAdj = getElementAdjustments(state, 'meta', elementKey, fallbackColor || theme.accent);
    x += logoAdj.dx;
    y += logoAdj.dy;
    maxW *= logoAdj.scale;
    maxH *= logoAdj.scale;

    const rec = requestLocalLogo(theme);
    if(rec && rec.loaded && rec.img.naturalWidth){
      const ratio = rec.img.naturalWidth / rec.img.naturalHeight;
      let w = maxW, h = w / ratio;
      if(h > maxH){ h = maxH; w = h * ratio; }
      const dx = align === 'right' ? x - w : x;
      ctx.drawImage(rec.img, dx, y, w, h);
      return {w, h, visible:true};
    }

    if(rec && rec.failed){
      const fontSize = Math.min(maxH * .78, 28);
      const color = logoAdj.color;
      drawText(ctx, theme.brand, x, y + maxH * .78, fontSize, color, '700', family, align);
      return {w:maxW, h:maxH, visible:true};
    }

    return {w:0, h:0, visible:false};
  }

  // Segmented digital font for film date overlay
  const SEG_POINTS = {
    T:[0.18,0.12, 0.82,0.12],
    M:[0.18,0.50, 0.82,0.50],
    B:[0.18,0.88, 0.82,0.88],
    UL:[0.12,0.18, 0.12,0.46],
    UR:[0.88,0.18, 0.88,0.46],
    LL:[0.12,0.54, 0.12,0.82],
    LR:[0.88,0.54, 0.88,0.82],
    CV:[0.50,0.14, 0.50,0.86],
    D1:[0.18,0.14, 0.50,0.50],
    D2:[0.82,0.14, 0.50,0.50],
    D3:[0.16,0.20, 0.50,0.84],
    D4:[0.84,0.20, 0.50,0.84],
    SL:[0.18,0.84, 0.82,0.16]
  };
  const SEG_MAP = {
    '0':['T','UL','UR','LL','LR','B'],
    '1':['UR','LR'],
    '2':['T','UR','M','LL','B'],
    '3':['T','UR','M','LR','B'],
    '4':['UL','UR','M','LR'],
    '5':['T','UL','M','LR','B'],
    '6':['T','UL','M','LL','LR','B'],
    '7':['T','UR','LR'],
    '8':['T','UL','UR','M','LL','LR','B'],
    '9':['T','UL','UR','M','LR','B'],
    'A':['T','UL','UR','M','LL','LR'],
    'B':['UL','LL','M','B','UR','LR'],
    'C':['T','UL','LL','B'],
    'D':['T','B','UL','LL','UR','LR'],
    'E':['T','UL','M','LL','B'],
    'F':['T','UL','M','LL'],
    'G':['T','UL','LL','B','LR','M'],
    'H':['UL','UR','M','LL','LR'],
    'I':['T','CV','B'],
    'J':['UR','LR','B','LL'],
    'K':['UL','LL','D2','D3'],
    'L':['UL','LL','B'],
    'M':['UL','UR','LL','LR','D1','D2'],
    'N':['UL','UR','LL','LR','D1','D4'],
    'O':['T','UL','UR','LL','LR','B'],
    'P':['T','UL','UR','M','LL'],
    'Q':['T','UL','UR','LL','LR','B','D4'],
    'R':['T','UL','UR','M','LL','D4'],
    'S':['T','UL','M','LR','B'],
    'T':['T','CV'],
    'U':['UL','UR','LL','LR','B'],
    'V':['UL','UR','D3','D4'],
    'W':['UL','UR','LL','LR','D3','D4'],
    'X':['D1','D2','D3','D4'],
    'Y':['D1','D2','CV'],
    'Z':['T','D2','D3','B'],
    '-':['M'],
    ' ':[]
  };

  function digitalCharWidth(size){ return size * 0.60; }
  function digitalGap(size){ return size * 0.14; }

  function measureDigitalText(text, size){
    const chars = String(text || '').toUpperCase();
    let total = 0;
    for(let i=0;i<chars.length;i++){
      const ch = chars[i];
      if(ch === '.') total += size * 0.18;
      else if(ch === '/') total += size * 0.34;
      else total += digitalCharWidth(size);
      if(i < chars.length - 1) total += digitalGap(size);
    }
    return total;
  }

  function drawDigitalText(ctx, text, x, y, size, color, align='left'){
    const chars = String(text || '').toUpperCase();
    const stroke = Math.max(1.5, size * 0.085);
    const gap = digitalGap(size);
    const totalWidth = measureDigitalText(chars, size);
    let cursor = x;
    if(align === 'right') cursor = x - totalWidth;
    if(align === 'center') cursor = x - totalWidth / 2;

    ctx.save();
    ctx.strokeStyle = color;
    ctx.fillStyle = color;
    ctx.lineWidth = stroke;
    ctx.lineCap = 'square';
    ctx.lineJoin = 'miter';
    ctx.shadowColor = 'rgba(0,0,0,.35)';
    ctx.shadowBlur = 1;
    ctx.shadowOffsetY = 1;

    [...chars].forEach(ch => {
      const cw = (ch === '.') ? size * 0.18 : (ch === '/' ? size * 0.34 : digitalCharWidth(size));
      if(ch === '.'){
        ctx.beginPath();
        ctx.arc(cursor + cw * 0.5, y + size * 0.82, stroke * 0.42, 0, Math.PI * 2);
        ctx.fill();
        cursor += cw + gap;
        return;
      }
      if(ch === '/'){
        ctx.beginPath();
        ctx.moveTo(cursor + cw * 0.12, y + size * 0.86);
        ctx.lineTo(cursor + cw * 0.88, y + size * 0.14);
        ctx.stroke();
        cursor += cw + gap;
        return;
      }
      const segs = SEG_MAP[ch] || [];
      segs.forEach(seg => {
        const [x1,y1,x2,y2] = SEG_POINTS[seg];
        ctx.beginPath();
        ctx.moveTo(cursor + cw * x1, y + size * y1);
        ctx.lineTo(cursor + cw * x2, y + size * y2);
        ctx.stroke();
      });
      cursor += cw + gap;
    });
    ctx.restore();
  }

  function horizontalAnchor(position, left, right){
    const p = Math.max(0, Math.min(100, Number(position || 0)));
    const x = left + (right - left) * (p / 100);

    if(p <= 33){
      return {
        x,
        align:'left',
        maxWidth:Math.max(40, right - x)
      };
    }

    if(p >= 67){
      return {
        x,
        align:'right',
        maxWidth:Math.max(40, x - left)
      };
    }

    return {
      x,
      align:'center',
      maxWidth:Math.max(40, Math.min(x - left, right - x) * 2)
    };
  }

  function fitHorizontalPosterText(ctx, text, maxWidth, maxLines, wantedSize, minSize, family, weight){
    return fitWrappedText(
      ctx,
      text,
      maxWidth,
      maxLines,
      wantedSize,
      minSize,
      family,
      weight
    );
  }

  function buildVerticalColumns(text, maxCharsPerColumn){
    const normalized = String(text || '').replace(/\r/g, '');
    const columns = [];
    let column = [];

    for(const character of normalized){
      if(character === '\n' || column.length >= maxCharsPerColumn){
        if(column.length) columns.push(column);
        column = [];
        if(character === '\n') continue;
      }
      column.push(character);
    }

    if(column.length) columns.push(column);
    return columns;
  }

  function drawVerticalPosterText(ctx, text, anchorX, anchorY, maxHeight, fontSize, minSize, color, family, weight='700', align='left', maxColumns=5){
    let size = fontSize;
    let columns = [];

    while(size >= minSize){
      const lineHeight = size * 1.05;
      const maxChars = Math.max(1, Math.floor(maxHeight / lineHeight));
      columns = buildVerticalColumns(text, maxChars);
      if(columns.length <= maxColumns) break;
      size -= 2;
    }

    size = Math.max(minSize, size);
    const lineHeight = size * 1.05;
    const columnGap = size * 1.18;
    const maxChars = Math.max(1, Math.floor(maxHeight / lineHeight));
    columns = buildVerticalColumns(text, maxChars).slice(0, maxColumns);

    const totalWidth = Math.max(size, columns.length * columnGap);
    let firstColumnX = anchorX;

    if(align === 'right'){
      firstColumnX = anchorX;
    }else if(align === 'center'){
      firstColumnX = anchorX + totalWidth / 2 - size / 2;
    }else{
      firstColumnX = anchorX + totalWidth - size;
    }

    ctx.save();
    ctx.fillStyle = color;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'top';
    ctx.shadowColor = 'rgba(0,0,0,0.32)';
    ctx.shadowBlur = 2;
    ctx.shadowOffsetY = 1;
    setFont(ctx, size, weight, family);

    columns.forEach((column, columnIndex) => {
      const columnX = firstColumnX - columnIndex * columnGap;
      column.forEach((character, charIndex) => {
        ctx.fillText(character, columnX, anchorY + charIndex * lineHeight);
      });
    });

    ctx.restore();
    return {size, width:totalWidth, height:Math.min(maxHeight, maxChars * lineHeight)};
  }

  function buildModel(state, measureCtx){
    const theme = effectiveTheme(state);
    const m = Number(state.margin);
    const radius = Number(state.radius);
    const ratio = photoRatio();
    const photoW = 1000;
    const photoH = photoW / ratio;
    const frameColor = state.frameColor;

    const fonts = { title: state.titleFont, body: state.bodyFont, meta: state.metaFont };

    const useCustomTextColors = state.textColorMode === 'custom';
    const lightPalette = {
      title: useCustomTextColors ? state.titleColor : '#171717',
      body: useCustomTextColors ? state.bodyColor : '#171717',
      meta: useCustomTextColors ? state.metaColor : '#5f5f5f'
    };
    const darkPalette = {
      title: useCustomTextColors ? state.titleColor : '#ffffff',
      body: useCustomTextColors ? state.bodyColor : '#f0f0f0',
      meta: useCustomTextColors ? state.metaColor : '#d8d8d8'
    };


    if(layout === 'stamp'){
      const W = photoW;
      const H = photoH;
      return {
        width: W, height: H,
        draw(ctx){
          ctx.fillStyle = '#111';
          ctx.fillRect(0,0,W,H);
          drawPhoto(ctx, 0, 0, W, H, 0);

          const stampColor = '#ff9f2e';
          const bottomOffset = Math.max(16, H * 0.035);
          const baseSize = Math.max(11, Math.min(16, H * 0.022));
          const lineTop = H - bottomOffset - baseSize;
          const brandStr = theme.brand.toUpperCase();
          const exifStr = stampExifLine(state);
          const dateStr = dateText(state).slice(2);

          const leftPad = Math.max(12, W * 0.018);
          const rightPad = leftPad;
          const brandMax = W * 0.19;
          const exifMax = W * 0.49;
          const dateMax = W * 0.22;

          function fittedSize(text, wanted, maxWidth, minSize=8){
            let size = wanted;
            while(size > minSize && measureDigitalText(text, size) > maxWidth) size -= 0.5;
            return size;
          }

          const logoAdj = getElementAdjustments(state, 'meta', 'logo', stampColor);
          const exifAdj = getElementAdjustments(state, 'exif', 'exif', stampColor);
          const brandSize = fittedSize(brandStr, baseSize * logoAdj.scale, brandMax, 8);
          const exifSize = fittedSize(exifStr, baseSize * exifAdj.scale, exifMax, 8);
          const dateSize = fittedSize(dateStr, (baseSize + 1) * exifAdj.scale, dateMax, 8);

          if(isActiveSetting(state, 'showLogo')){
            drawDigitalText(ctx, brandStr, leftPad + logoAdj.dx, lineTop + logoAdj.dy, brandSize, stampColor, 'left');
          }
          if(isActiveSetting(state, 'showExif')){
            drawDigitalText(ctx, exifStr, W * 0.49 + exifAdj.dx, lineTop + exifAdj.dy, exifSize, stampColor, 'center');
            drawDigitalText(ctx, dateStr, W - rightPad + exifAdj.dx, lineTop + exifAdj.dy, dateSize, stampColor, 'right');
          }
        }
      };
    }

    if(layout === 'gallery'){
      const footerBase = 168;
      const projectH = isActiveSetting(state,'showProject') ? 34 : 0;
      const noteLines = isActiveSetting(state,'showNote') ? wrapLines(measureCtx, state.note, photoW, 18, fonts.body, '400', 4).length : 0;
      const footer = footerBase + projectH + noteLines * 26;
      const W = photoW + m * 2;
      const H = photoH + m * 2 + footer;
      return {
        width: W, height: H,
        draw(ctx){
          const fg = lightPalette.title;
          const bodyFg = lightPalette.body;
          const muted = lightPalette.meta;
          drawFrameSurface(ctx, 0, 0, W, H, frameColor);
          drawPhoto(ctx, m, m, photoW, photoH, radius);

          const metaTop = m + photoH + 34;
          const showBrand = isActiveSetting(state,'showLogo');
          const showExif = isActiveSetting(state,'showExif');

          if(showBrand) drawBrand(ctx, theme, state, m, metaTop - 8, 250, 30, fonts.meta, 'left', lightPalette.meta);

          if(showExif){
            drawManagedText(ctx, state, 'exif', state.model, W - m, metaTop + 18, 28, lightPalette.meta, '700', fonts.meta, 'right');
            drawManagedFittedText(ctx, state, 'exif', state.lens, m, metaTop + 52, W * 0.58, 22, 12, lightPalette.meta, '500', fonts.meta);
            drawManagedFittedText(ctx, state, 'exif', exifLine(state), m, metaTop + 86, W * 0.62, 21, 11, lightPalette.meta, '400', fonts.meta);
            if(isActiveSetting(state,'showLocation')){
              drawManagedFittedText(ctx, state, 'location', `${dateText(state)}  ${state.location}`, W - m, metaTop + 86, W * 0.34, 20, 11, lightPalette.meta, '400', fonts.meta, 'right');
            } else {
              drawManagedFittedText(ctx, state, 'exif', `${dateText(state)}`, W - m, metaTop + 86, W * 0.24, 20, 11, lightPalette.meta, '400', fonts.meta, 'right');
            }
          } else if(isActiveSetting(state,'showLocation')){
            drawManagedFittedText(ctx, state, 'location', state.location, W - m, metaTop + 20, W * 0.42, 21, 12, lightPalette.meta, '500', fonts.meta, 'right');
          }

          let yy = metaTop + (showExif ? 122 : 58);
          if(isActiveSetting(state,'showProject')){
            drawManagedText(ctx, state, 'meta', 'PROJECT', m, yy, 15, muted, '700', fonts.meta, 'left', false, 'project');
            drawManagedText(ctx, state, 'body', state.project, m + 92, yy, 22, fg, '700', fonts.title, 'left', false, 'project');
            yy += 28;
          }
          if(isActiveSetting(state,'showNote')){
            drawManagedWrappedText(ctx, state, 'body', state.note, m, yy, W - 2*m, 27, 18, lightPalette.body, fonts.body, '400', 4, 'left', 'note');
          }
        }
      };
    }

    if(layout === 'contact'){
      const topInfoBand = 44;
      const photoY = 98;
      const afterPhotoGap = 28;
      const titleH = isActiveSetting(state,'showTitle') ? 36 : 0;
      const promptH = isActiveSetting(state,'showPrompt') ? 26 : 0;
      const thoughtLines = isActiveSetting(state,'showThought') ? wrapLines(measureCtx, state.thought, photoW - 60, 23, fonts.body, '400', 5).length : 0;
      const thoughtH = isActiveSetting(state,'showThought') ? thoughtLines * 32 : 0;
      const infoBottomBand = 46;
      const contentBlockH = titleH + promptH + thoughtH + 18;
      const bottomSafeGap = 34;
      const W = photoW + (m + 28) * 2;
      const H = photoY + photoH + afterPhotoGap + contentBlockH + bottomSafeGap + infoBottomBand + 52;
      return {
        width: W, height: H,
        draw(ctx){
          ctx.fillStyle = '#0a0a0a';
          ctx.fillRect(0,0,W,H);

          const holeCount = 16;
          const innerW = W - 2*m;
          for(let i=0;i<holeCount;i++){
            const hx = m + i * (innerW / holeCount) + 4;
            ctx.fillStyle = '#c8c8c8';
            roundedRectPath(ctx, hx, 14, 32, 40, 6); ctx.fill();
            roundedRectPath(ctx, hx, H - 54, 32, 40, 6); ctx.fill();
          }

          const showBrand = isActiveSetting(state,'showLogo');
          const showExif = isActiveSetting(state,'showExif');

          if(showBrand) drawBrand(ctx, theme, state, m + 14, 62, 200, 24, fonts.meta, 'left', darkPalette.meta);
          if(showExif) drawManagedFittedText(ctx, state, 'exif', exifLine(state), W - (m + 14), 82, W * 0.42, 18, 11, darkPalette.meta, '600', fonts.meta, 'right');

          const photoX = m + 28;
          drawPhoto(ctx, photoX, photoY, photoW, photoH, radius);
          ctx.strokeStyle = '#252525';
          ctx.lineWidth = 8;
          ctx.strokeRect(photoX, photoY, photoW, photoH);

          let yy = photoY + photoH + afterPhotoGap;
          if(isActiveSetting(state,'showTitle')){
            drawManagedText(ctx, state, 'title', state.title, W/2, yy, 28, darkPalette.title, '700', fonts.title, 'center');
            yy += 36;
          }
          if(isActiveSetting(state,'showPrompt')){
            drawManagedText(ctx, state, 'body', state.promptText, W/2, yy, 17, darkPalette.meta, '600', fonts.body, 'center', false, 'prompt');
            yy += 26;
          }
          if(isActiveSetting(state,'showThought')){
            drawManagedWrappedText(ctx, state, 'body', state.thought, W/2, yy, photoW - 60, 32, 23, darkPalette.body, fonts.body, '400', 5, 'center', 'thought');
          }

          const bottomInfoY = H - 70;
          if(showExif){
            drawManagedFittedText(ctx, state, 'exif', state.model, m + 14, bottomInfoY, W * 0.42, 18, 12, darkPalette.meta, '500', fonts.meta);
            drawManagedFittedText(ctx, state, 'exif', dateText(state), W - (m + 14), bottomInfoY, W * 0.20, 18, 12, darkPalette.meta, '600', fonts.meta, 'right');
          }
        }
      };
    }

    if(layout === 'poster'){
      const showTitle = isActiveSetting(state,'showTitle');
      const showThought = isActiveSetting(state,'showThought');
      const showLocation = isActiveSetting(state,'showLocation');
      const showProject = isActiveSetting(state,'showProject');
      const showBrand = isActiveSetting(state,'showLogo');
      const showExif = isActiveSetting(state,'showExif');

      // Poster Overlay is photo-only: no outer frame, no external margin.
      const W = photoW;
      const H = photoH;

      return {
        width: W, height: H,
        draw(ctx){
          drawPhoto(ctx, 0, 0, photoW, photoH, 0);

          const photoTop = 0;
          const photoBottom = photoH;
          const photoLeft = 0;
          const photoRight = photoW;

          // Visual safe area for project, logo, location, and EXIF.
          // Text no longer sits directly on the photo/frame edge.
          const edgeInsetX = Math.max(26, Math.min(44, photoW * 0.038));
          const edgeInsetTop = Math.max(28, Math.min(42, photoH * 0.048));
          const edgeInsetBottom = Math.max(30, Math.min(46, photoH * 0.052));
          const contentLeft = photoLeft + edgeInsetX;
          const contentRight = photoRight - edgeInsetX;

          const topReserve = Math.max(64, photoH * 0.11);
          const bottomReserve = Math.max(60, photoH * 0.10);

          const lowerGradientH = Math.max(300, photoH * 0.62);
          fillGradientRect(
            ctx,
            photoLeft,
            photoBottom - lowerGradientH,
            photoW,
            lowerGradientH,
            'vertical',
            [
              [0, 'rgba(0,0,0,0)'],
              [0.40, 'rgba(0,0,0,0.16)'],
              [0.72, 'rgba(0,0,0,0.56)'],
              [1, 'rgba(0,0,0,0.82)']
            ]
          );

          const upperGradientH = Math.max(100, photoH * 0.18);
          fillGradientRect(
            ctx,
            photoLeft,
            photoTop,
            photoW,
            upperGradientH,
            'vertical',
            [
              [0, 'rgba(0,0,0,0.48)'],
              [1, 'rgba(0,0,0,0)']
            ]
          );

          const identityY = photoTop + edgeInsetTop;

          if(showProject){
            drawManagedFittedText(
              ctx,
              state,
              'meta',
              state.project.toUpperCase(),
              contentLeft,
              identityY,
              photoW * 0.44,
              19,
              11,
              darkPalette.meta,
              '700',
              fonts.meta,
              'left',
              'project'
            );
          }

          if(showBrand){
            drawBrand(
              ctx,
              theme,
              state,
              contentRight,
              identityY - 20,
              Math.min(190, photoW * 0.24),
              25,
              fonts.meta,
              'right',
              darkPalette.meta
            );
          }

          const titleAnchor = horizontalAnchor(state.posterTitleX, photoLeft, photoRight);
          const bodyAnchor = horizontalAnchor(state.posterBodyX, photoLeft, photoRight);
          const titlePosY = Math.max(0, Math.min(100, Number(state.posterTitleY || 72)));
          const bodyPosY = Math.max(0, Math.min(100, Number(state.posterBodyY || 84)));
          const titleAdj = getElementAdjustments(state, 'title', 'title', darkPalette.title);
          const bodyAdj = getElementAdjustments(state, 'body', 'thought', darkPalette.body);
          const locationAdj = getElementAdjustments(state, 'location', 'location', darkPalette.meta);
          const titleSize = Math.max(24, Math.min(140, Number(state.posterTitleSize || 66))) * titleAdj.scale;
          const bodySize = Math.max(12, Math.min(72, Number(state.posterBodySize || 22))) * bodyAdj.scale;
          const titleVertical = state.posterTitleDirection === 'vertical';
          const bodyVertical = state.posterBodyDirection === 'vertical';

          const contentTop = photoTop + topReserve;
          const contentBottom = photoBottom - bottomReserve;
          const contentHeight = Math.max(80, contentBottom - contentTop);

          const titleY = contentTop + contentHeight * (titlePosY / 100) + titleAdj.dy;
          const bodyY = contentTop + contentHeight * (bodyPosY / 100) + bodyAdj.dy;

          if(showTitle){
            if(titleVertical){
              const verticalTitleY = Math.max(photoTop, Math.min(titleY, photoBottom - 40));
              drawVerticalPosterText(
                ctx,
                state.title,
                titleAnchor.x + titleAdj.dx,
                verticalTitleY,
                Math.max(40, photoBottom - verticalTitleY),
                titleSize,
                20,
                titleAdj.color,
                fonts.title,
                '700',
                titleAnchor.align,
                6
              );
            }else{
              const fit = fitHorizontalPosterText(
                ctx,
                state.title,
                titleAnchor.maxWidth,
                5,
                titleSize,
                22,
                fonts.title,
                '700'
              );

              const titleHeight = fit.lines.length * fit.lineHeight;
              const boundedTitleY = Math.max(
                photoTop,
                Math.min(titleY, photoBottom - titleHeight)
              );

              ctx.save();
              ctx.fillStyle = titleAdj.color;
              ctx.textAlign = titleAnchor.align;
              ctx.textBaseline = 'top';
              ctx.shadowColor = 'rgba(0,0,0,0.16)';
              ctx.shadowBlur = 2;
              ctx.shadowOffsetX = 1;
              ctx.shadowOffsetY = 1;
              setFont(ctx, fit.size, '700', fonts.title);

              fit.lines.forEach((lineText, index) => {
                ctx.fillText(
                  lineText,
                  titleAnchor.x + titleAdj.dx,
                  boundedTitleY + index * fit.lineHeight
                );
              });
              ctx.restore();
            }
          }

          if(showThought){
            if(bodyVertical){
              const verticalBodyY = Math.max(photoTop, Math.min(bodyY, photoBottom - 30));
              drawVerticalPosterText(
                ctx,
                state.thought,
                bodyAnchor.x + bodyAdj.dx,
                verticalBodyY,
                Math.max(30, photoBottom - verticalBodyY),
                bodySize,
                11,
                bodyAdj.color,
                fonts.body,
                '500',
                bodyAnchor.align,
                8
              );
            }else{
              const fit = fitHorizontalPosterText(
                ctx,
                state.thought,
                bodyAnchor.maxWidth,
                7,
                bodySize,
                11,
                fonts.body,
                '500'
              );

              const bodyLineHeight = fit.lineHeight * bodyAdj.lineHeightScale;
              const bodyHeight = fit.lines.length * bodyLineHeight;
              const boundedBodyY = Math.max(
                photoTop,
                Math.min(bodyY, photoBottom - bodyHeight)
              );

              ctx.save();
              ctx.fillStyle = bodyAdj.color;
              ctx.textAlign = bodyAnchor.align;
              ctx.textBaseline = 'top';
              ctx.shadowColor = 'rgba(0,0,0,0.16)';
              ctx.shadowBlur = 2;
              ctx.shadowOffsetX = 1;
              ctx.shadowOffsetY = 1;
              setFont(ctx, fit.size, '500', fonts.body);

              fit.lines.forEach((lineText, index) => {
                ctx.fillText(
                  lineText,
                  bodyAnchor.x + bodyAdj.dx,
                  boundedBodyY + index * bodyLineHeight
                );
              });
              ctx.restore();
            }
          }

          const metadataY = photoBottom - edgeInsetBottom;

          if(showLocation){
            drawManagedFittedText(
              ctx,
              state,
              'location',
              state.location,
              contentLeft,
              metadataY,
              photoW * 0.38,
              16,
              10,
              locationAdj.color,
              '600',
              fonts.meta,
              'left'
            );
          }

          if(showExif){
            const exifBlock = [
              state.model,
              exifLine(state),
              dateText(state)
            ].filter(Boolean).join('  ·  ');

            drawManagedFittedText(
              ctx,
              state,
              'exif',
              exifBlock,
              contentRight,
              metadataY,
              photoW * 0.48,
              15,
              9,
              darkPalette.meta,
              '500',
              fonts.meta,
              'right'
            );
          }
        }
      };
    }

    if(layout === 'frameonly'){
      const W = photoW + m * 2;
      const H = photoH + m * 2;
      return {
        width: W, height: H,
        draw(ctx){
          drawFrameSurface(ctx, 0, 0, W, H, frameColor);
          drawPhoto(ctx, m, m, photoW, photoH, radius);
        }
      };
    }

    if(layout === 'minimal'){
      const showBrand = isActiveSetting(state,'showLogo');
      const showExif = isActiveSetting(state,'showExif');
      const showLocation = isActiveSetting(state,'showLocation');
      const barH = showExif ? 106 : 68;
      const W = photoW + m * 2;
      const H = photoH + m * 2 + barH;

      return {
        width: W, height: H,
        draw(ctx){
          const fg = lightPalette.title;
          const muted = lightPalette.meta;

          drawFrameSurface(ctx, 0, 0, W, H, frameColor);
          drawPhoto(ctx, m, m, photoW, photoH, radius);

          const barTop = m + photoH + 22;

          if(showBrand){
            drawBrand(ctx, theme, state, m, barTop - 2, 185, 26, fonts.meta, 'left', lightPalette.meta);
          }

          if(showExif){
            const modelX = showBrand ? m + 215 : m;
            drawManagedFittedText(ctx, state, 'exif', state.model, modelX, barTop + 20, W * 0.25, 21, 12, lightPalette.meta, '700', fonts.meta);
            drawManagedFittedText(ctx, state, 'exif', exifLine(state), W - m, barTop + 20, W * 0.44, 18, 10, lightPalette.meta, '500', fonts.meta, 'right');

            if(showLocation){
              drawManagedFittedText(ctx, state, 'location', state.location, m, barTop + 56, W * 0.55, 16, 10, muted, '500', fonts.meta);
            }
            drawManagedFittedText(ctx, state, 'exif', dateText(state), W - m, barTop + 56, W * 0.24, 16, 10, muted, '500', fonts.meta, 'right');
          } else if(showLocation){
            drawManagedFittedText(ctx, state, 'location', state.location, W - m, barTop + 24, W * 0.46, 18, 11, muted, '500', fonts.meta, 'right');
          }
        }
      };
    }

    if(layout === 'caption'){
      const showTitle = isActiveSetting(state,'showTitle');
      const showThought = isActiveSetting(state,'showThought');
      const showLocation = isActiveSetting(state,'showLocation');
      const showExif = isActiveSetting(state,'showExif');

      const thoughtLines = showThought
        ? wrapLines(measureCtx, state.thought, photoW, 25, fonts.body, '400', 5).length
        : 0;

      const titleH = showTitle ? 56 : 0;
      const thoughtH = showThought ? thoughtLines * 34 + 16 : 0;
      const bottomMetaGap = (showThought && (showLocation || showExif)) ? 20 : 0;
      const bottomLineH = (showLocation || showExif) ? 32 : 0;
      const captionH = 48 + titleH + thoughtH + bottomMetaGap + bottomLineH + 24;

      const W = photoW + m * 2;
      const H = photoH + m * 2 + captionH;

      return {
        width: W, height: H,
        draw(ctx){
          const fg = lightPalette.title;
          const bodyFg = lightPalette.body;
          const muted = lightPalette.meta;

          drawFrameSurface(ctx, 0, 0, W, H, frameColor);
          drawPhoto(ctx, m, m, photoW, photoH, radius);

          let yy = m + photoH + 50;

          if(showTitle){
            drawManagedFittedText(ctx, state, 'title', state.title, m, yy, photoW, 38, 18, fg, '700', fonts.title);
            yy += 54;
          }

          if(showThought){
            yy += drawManagedWrappedText(ctx, state, 'body', state.thought, m, yy, photoW, 34, 25, bodyFg, fonts.body, '400', 5, 'left', 'thought');
            yy += 16;
          }

          if(showThought && (showLocation || showExif)){
            yy += bottomMetaGap;
          }

          if(showLocation){
            drawManagedFittedText(ctx, state, 'location', state.location, m, yy, photoW * 0.52, 18, 10, muted, '600', fonts.meta);
          }

          if(showExif){
            const exifBlock = [state.model, exifLine(state), dateText(state)]
              .filter(Boolean)
              .join('  ·  ');
            drawManagedFittedText(ctx, state, 'exif', exifBlock, W - m, yy, photoW * 0.46, 17, 9, muted, '500', fonts.meta, 'right');
          }
        }
      };
    }

    if(layout === 'polaroid'){
      const showTitle = isActiveSetting(state,'showTitle');
      const showNote = isActiveSetting(state,'showNote');
      const showLocation = isActiveSetting(state,'showLocation');
      const showProject = isActiveSetting(state,'showProject');
      const showExif = isActiveSetting(state,'showExif');

      const noteFontSize = 21;
      const noteLineHeight = 30;
      const maxNoteLines = 7;
      const noteLines = showNote
        ? wrapLines(
            measureCtx,
            state.note,
            photoW * 0.92,
            noteFontSize,
            fonts.body,
            '400',
            maxNoteLines
          ).length
        : 0;

      const headerBlockH = 52;
      const exifBlockH = showExif ? 32 : 0;
      const projectLocationH = (showProject || showLocation) ? 36 : 0;
      const noteBlockH = showNote ? noteLines * noteLineHeight : 0;

      // Keep about 3.5 lines of empty space under the note.
      const bottomBreathingRoom = 105;

      const lowerH =
        headerBlockH +
        exifBlockH +
        projectLocationH +
        noteBlockH +
        bottomBreathingRoom;

      const W = photoW + m * 2;
      const H = photoH + m * 2 + lowerH;

      return {
        width: W, height: H,
        draw(ctx){
          const fg = lightPalette.title;
          const bodyFg = lightPalette.body;
          const muted = lightPalette.meta;

          drawFrameSurface(ctx, 0, 0, W, H, frameColor);
          drawPhoto(ctx, m, m, photoW, photoH, radius);

          let yy = m + photoH + 50;

          if(showTitle){
            drawManagedFittedText(
              ctx,
              state,
              'title',
              state.title,
              m + 8,
              yy,
              photoW * 0.66,
              30,
              16,
              fg,
              '700',
              fonts.title
            );

            if(showExif){
              drawManagedFittedText(
                ctx,
                state,
                'exif',
                dateText(state),
                W - m - 8,
                yy,
                photoW * 0.24,
                17,
                10,
                muted,
                '600',
                fonts.meta,
                'right'
              );
            }
          }

          yy += headerBlockH;

          if(showExif){
            const exifBlock = [state.model, exifLine(state)]
              .filter(Boolean)
              .join('  ·  ');

            drawManagedFittedText(
              ctx,
              state,
              'exif',
              exifBlock,
              m + 8,
              yy,
              photoW * 0.92,
              16,
              9,
              muted,
              '500',
              fonts.meta
            );

            yy += exifBlockH;
          }

          if(showProject || showLocation){
            if(showProject){
              drawManagedText(
                ctx,
                state,
                'meta',
                'PROJECT',
                m + 8,
                yy,
                13,
                muted,
                '700',
                fonts.meta,
                'left',
                false,
                'project'
              );

              drawManagedFittedText(
                ctx,
                state,
                'body',
                state.project,
                m + 86,
                yy,
                photoW * 0.40,
                18,
                10,
                fg,
                '700',
                fonts.title,
                'left',
                'project'
              );
            }

            if(showLocation){
              drawManagedFittedText(
                ctx,
                state,
                'location',
                state.location,
                W - m - 8,
                yy,
                photoW * 0.38,
                16,
                9,
                muted,
                '500',
                fonts.meta,
                'right'
              );
            }

            yy += projectLocationH;
          }

          if(showNote){
            drawManagedWrappedText(
              ctx,
              state,
              'body',
              state.note,
              m + 8,
              yy,
              photoW * 0.92,
              noteLineHeight,
              noteFontSize,
              bodyFg,
              fonts.body,
              '400',
              maxNoteLines,
              'left',
              'note'
            );
          }
        }
      };
    }

    // Journal B
    const titleSize = 36;
    const locationSize = 22;
    const topGap = (isActiveSetting(state,'showTitle') || isActiveSetting(state,'showLocation')) ? Math.round(titleSize * 0.5) : 0;
    const headerBand = (isActiveSetting(state,'showTitle') || isActiveSetting(state,'showLocation')) ? titleSize + topGap : 0;
    const photoY = m + headerBand;
    const photoX = m;

    const metaGap = 44;
    const logoBlockHeight = 34;
    const logoToTextGap = 20;
    const modelFontSize = 25;
    const contentW = photoW;
    const leftW = Math.min(340, contentW * 0.32);
    const rx = m + leftW + 44;
    const rw = (m + photoW) - rx;

    const promptH = isActiveSetting(state,'showPrompt') ? 28 : 0;
    const thoughtLines = isActiveSetting(state,'showThought') ? wrapLines(measureCtx, state.thought, rw, 24, fonts.body, '400', 5).length : 0;
    const noteLines = isActiveSetting(state,'showNote') ? wrapLines(measureCtx, state.note, rw, 24, fonts.body, '400', 4).length : 0;
    const thoughtH = isActiveSetting(state,'showThought') ? 24 + thoughtLines * 34 + 16 : 0;
    const noteH = isActiveSetting(state,'showNote') ? 24 + noteLines * 34 : 0;
    const rightContentH = promptH + thoughtH + noteH;
    const journalBrandVisible = isActiveSetting(state,'showLogo');
    const journalExifVisible = isActiveSetting(state,'showExif');
    const logoSectionH = journalBrandVisible ? logoBlockHeight + logoToTextGap : 0;
    const exifSectionH = journalExifVisible ? modelFontSize + metaGap * 3 + 18 : 0;
    const leftContentH = logoSectionH + exifSectionH;
    const contentH = Math.max(rightContentH, leftContentH);
    const footerBand = (isActiveSetting(state,'showProject') || isActiveSetting(state,'showRating')) ? 56 : 12;

    const W = photoW + m * 2;
    const H = photoY + photoH + 34 + contentH + 30 + footerBand + m;

    return {
      width: W, height: H,
      draw(ctx){
        const fg = lightPalette.title;
        const bodyFg = lightPalette.body;
        const muted = lightPalette.meta;
        ctx.fillStyle = frameColor;
        ctx.fillRect(0,0,W,H);

        if(isActiveSetting(state,'showTitle')){
          drawManagedText(ctx, state, 'title', state.title, m, m + titleSize, titleSize, fg, '700', fonts.title);
        }
        if(isActiveSetting(state,'showLocation')){
          drawManagedText(ctx, state, 'location', state.location, W - m, m + locationSize + 8, locationSize, fg, '600', fonts.title, 'right');
        }

        drawPhoto(ctx, photoX, photoY, photoW, photoH, radius);
        line(ctx, m, photoY + photoH + 26, W - m, photoY + photoH + 26, '#cfc5b8', 1);

        const colsY = photoY + photoH + 56;
        const dividerX = m + leftW;
        line(ctx, dividerX, colsY - 18, dividerX, H - footerBand - 10, '#cfc5b8', 1);

        const brandVisible = isActiveSetting(state, 'showLogo');
        const exifVisible = isActiveSetting(state, 'showExif');
        const logoY = colsY - 8;
        let logoBottom = colsY;

        if(brandVisible){
          const brandBox = drawBrand(
            ctx,
            theme,
            state,
            m,
            logoY,
            250,
            logoBlockHeight,
            fonts.meta,
            'left',
            lightPalette.meta
          );
          logoBottom = logoY + Math.max(brandBox.h || 0, logoBlockHeight);
        }

        /*
          The first metadata line uses a baseline.  Adding only a fixed row gap
          can make tall fonts overlap the logo, so the baseline is calculated
          from the actual logo block bottom plus a separate visual gap and the
          model font's ascent allowance.
        */
        const metaStartY = brandVisible
          ? logoBottom + logoToTextGap + modelFontSize * 0.82
          : colsY + modelFontSize * 0.82;

        const metaTextWidth = Math.max(120, leftW - 22);

        if(exifVisible){
          drawManagedFittedText(ctx, state, 'exif', state.model, m, metaStartY, metaTextWidth, modelFontSize, 14, lightPalette.meta, '600', fonts.meta);
          drawManagedFittedText(ctx, state, 'exif', state.lens, m, metaStartY + metaGap, metaTextWidth, 22, 12, lightPalette.meta, '400', fonts.meta);
          drawManagedFittedText(ctx, state, 'exif', exifLine(state), m, metaStartY + metaGap * 2, metaTextWidth, 21, 11, lightPalette.meta, '400', fonts.meta);
          drawManagedFittedText(ctx, state, 'exif', `${dateText(state)}  ${state.time}`, m, metaStartY + metaGap * 3, metaTextWidth, 21, 11, lightPalette.meta, '400', fonts.meta);
        }

        let yy = colsY;
        if(isActiveSetting(state,'showPrompt')){
          drawManagedText(ctx, state, 'body', state.promptText, rx, yy, 18, lightPalette.meta, '700', fonts.meta, 'left', false, 'prompt');
          yy += 28;
        }
        if(isActiveSetting(state,'showThought')){
          drawManagedText(ctx, state, 'meta', 'THOUGHT', rx, yy, 15, muted, '700', fonts.meta, 'left', false, 'thought');
          yy += 24;
          yy += drawManagedWrappedText(ctx, state, 'body', state.thought, rx, yy, rw, 34, 24, bodyFg, fonts.body, '400', 5, 'left', 'thought');
          yy += 16;
        }
        if(isActiveSetting(state,'showNote')){
          if(isActiveSetting(state,'showThought')){
            line(ctx, rx, yy, rx + rw, yy, '#cfc5b8', 1);
            yy += 22;
          }
          drawManagedText(ctx, state, 'meta', 'NOTE', rx, yy, 15, muted, '700', fonts.meta, 'left', false, 'note');
          yy += 24;
          drawManagedWrappedText(ctx, state, 'body', state.note, rx, yy, rw, 34, 24, bodyFg, fonts.body, '400', 4, 'left', 'note');
        }

        if(isActiveSetting(state,'showProject') || isActiveSetting(state,'showRating')){
          line(ctx, m, H - footerBand - 8, W - m, H - footerBand - 8, '#cfc5b8', 1);
          const footerY = H - 16;
          if(isActiveSetting(state,'showProject')){
            drawManagedText(ctx, state, 'meta', 'PROJECT', m, footerY, 15, muted, '700', fonts.meta, 'left', false, 'project');
            drawManagedText(ctx, state, 'body', state.project, m + 92, footerY, 23, fg, '700', fonts.title, 'left', false, 'project');
          }
          if(isActiveSetting(state,'showRating')){
            const ratingAdj = getElementAdjustments(state, 'meta', 'rating', lightPalette.meta);
            const starSize = 23 * ratingAdj.scale;
            const estimatedStarWidth = starSize * 5.2;
            drawText(ctx, 'RATING', W - m - estimatedStarWidth - 78 + ratingAdj.dx, footerY + ratingAdj.dy, 15 * ratingAdj.scale, muted, '700', fonts.meta);
            stars(ctx, W - m + ratingAdj.dx, footerY + ratingAdj.dy, Number(state.rating), ratingAdj.color, starSize, fonts.meta, 'right');
          }
        }
      }
    };
  }

