  function renderPreview(){
    const state = getState();
    stylesForLayout(layout);
    updateControlVisibility();

    const measureCanvas = document.createElement('canvas');
    const mctx = measureCanvas.getContext('2d');
    const model = buildModel(state, mctx);
    const targetLongEdge = 1200;
    const scale = targetLongEdge / Math.max(model.width, model.height);

    previewCanvas.width = Math.round(model.width * scale);
    previewCanvas.height = Math.round(model.height * scale);
    previewCtx.setTransform(scale, 0, 0, scale, 0, 0);
    model.draw(previewCtx);
    drawUniversalOverlays(previewCtx, state, model);

    $('statusText').textContent = '준비됨';
    $('canvasInfo').textContent = `${previewCanvas.width} × ${previewCanvas.height} preview`;
  }

  function isSafariBrowser(){
    const ua = navigator.userAgent;
    return /Safari/i.test(ua) && !/Chrome|Chromium|CriOS|Edg|OPR|Android/i.test(ua);
  }

  function safeCanvasPixelLimit(){
    return isSafariBrowser() ? 16000000 : 48000000;
  }

  function selectedLogoReady(state){
    const watermarkRecord = state.showWatermark && state.watermarkDataUrl ? getWatermarkImage(state.watermarkDataUrl) : null;
    if(watermarkRecord && !watermarkRecord.loaded && !watermarkRecord.failed) return false;

    if(layout === 'stamp' || !isActiveSetting(state, 'showLogo')){
      return true;
    }

    const theme = effectiveTheme(state);
    const record = requestLocalLogo(theme);

    /*
      Export is intentionally synchronous so Safari keeps the original
      button-click permission.  If an image logo is still loading, the user
      must click once more after it has appeared in the preview.
    */
    return !record || record.loaded || record.failed;
  }

  function dataUrlToBlob(dataUrl){
    const comma = dataUrl.indexOf(',');
    if(comma < 0) return null;

    const header = dataUrl.slice(0, comma);
    const payload = dataUrl.slice(comma + 1);
    const mimeMatch = header.match(/^data:([^;]+)/i);
    const mime = mimeMatch ? mimeMatch[1] : 'image/jpeg';

    const binary = atob(payload);
    const bytes = new Uint8Array(binary.length);

    for(let i=0; i<binary.length; i++){
      bytes[i] = binary.charCodeAt(i);
    }

    return new Blob([bytes], {type:mime});
  }


  function directoryPickerSupported(){
    return typeof window.showDirectoryPicker === 'function';
  }

  function updateSaveDirStatus(message=''){
    const el = $('saveDirStatus');
    if(!el) return;
    if(message){
      el.textContent = message;
      return;
    }
    if(saveDirectoryHandle){
      el.textContent = `저장 폴더: ${saveDirectoryHandle.name} · 현재/전체 저장 시 이 폴더에 직접 저장`;
    }else if(directoryPickerSupported()){
      el.textContent = '저장 폴더 미선택 · 선택하면 JPEG/일괄 결과를 해당 폴더에 직접 저장';
    }else{
      el.textContent = '이 브라우저는 폴더 직접 저장을 지원하지 않습니다. 일반 다운로드/ZIP으로 저장됩니다.';
    }
  }

  async function chooseSaveDirectory(){
    if(!directoryPickerSupported()){
      alert('이 브라우저는 저장 폴더 직접 선택을 지원하지 않습니다. Chrome 또는 Edge 사용을 권장합니다.');
      updateSaveDirStatus();
      return null;
    }
    try{
      const handle = await window.showDirectoryPicker({mode:'readwrite'});
      saveDirectoryHandle = handle;
      updateSaveDirStatus();
      $('statusText').textContent = `저장 폴더 선택 완료: ${handle.name}`;
      return handle;
    }catch(error){
      if(error && error.name === 'AbortError'){
        $('statusText').textContent = '저장 폴더 선택 취소';
        return null;
      }
      console.error('Directory picker failed:', error);
      alert(`저장 폴더를 선택하지 못했습니다.

${error && error.message ? error.message : String(error)}`);
      return null;
    }
  }

  function clearSaveDirectory(){
    saveDirectoryHandle = null;
    updateSaveDirStatus();
    $('statusText').textContent = '저장 폴더 선택 해제';
  }

  async function ensureDirectoryPermission(handle){
    if(!handle) return false;
    if(handle.queryPermission){
      const current = await handle.queryPermission({mode:'readwrite'});
      if(current === 'granted') return true;
    }
    if(handle.requestPermission){
      const next = await handle.requestPermission({mode:'readwrite'});
      return next === 'granted';
    }
    return false;
  }

  function splitFileName(name){
    const match = /^(.*?)(\.[^.]+)?$/.exec(name || 'file');
    return {base: match?.[1] || 'file', ext: match?.[2] || ''};
  }

  async function getUniqueFileHandle(dirHandle, fileName){
    const {base, ext} = splitFileName(fileName);
    let candidate = `${base}${ext}`;
    let count = 1;
    while(true){
      try{
        await dirHandle.getFileHandle(candidate, {create:false});
        candidate = `${base}_${count}${ext}`;
        count += 1;
      }catch(error){
        const handle = await dirHandle.getFileHandle(candidate, {create:true});
        return {handle, fileName: candidate};
      }
    }
  }

  async function writeBlobToDirectory(dirHandle, fileName, blob){
    const {handle, fileName: finalName} = await getUniqueFileHandle(dirHandle, fileName);
    const writable = await handle.createWritable();
    await writable.write(blob);
    await writable.close();
    return finalName;
  }

  async function getExportDirectoryHandle({promptIfNeeded=true} = {}){
    if(!directoryPickerSupported()) return null;
    if(saveDirectoryHandle){
      const ok = await ensureDirectoryPermission(saveDirectoryHandle);
      if(ok) return saveDirectoryHandle;
    }
    if(!promptIfNeeded) return null;
    const handle = await chooseSaveDirectory();
    if(!handle) return null;
    const ok = await ensureDirectoryPermission(handle);
    if(!ok){
      alert('선택한 폴더에 쓰기 권한을 얻지 못했습니다. 일반 다운로드 방식으로 진행합니다.');
      return null;
    }
    return handle;
  }

  function prepareAndStartDownload(blob, fileName, message, downloadLabel='다운로드'){
    if(preparedDownloadUrl){
      URL.revokeObjectURL(preparedDownloadUrl);
    }

    preparedDownloadUrl = URL.createObjectURL(blob);

    const panel = $('downloadResult');
    const link = $('preparedDownloadLink');
    const messageEl = $('downloadMessage');

    link.href = preparedDownloadUrl;
    link.download = fileName;
    link.textContent = downloadLabel;
    messageEl.textContent = message;
    panel.hidden = false;

    /*
      This click runs in the same synchronous call stack as the user's export
      button click.  That preserves Safari's user-activation permission.
      The visible link remains available as a manual fallback.
    */
    const temporaryLink = document.createElement('a');
    temporaryLink.href = preparedDownloadUrl;
    temporaryLink.download = fileName;
    temporaryLink.style.display = 'none';
    document.body.appendChild(temporaryLink);

    try{
      temporaryLink.click();
    }finally{
      temporaryLink.remove();
    }
  }


  function generateJPEGBlobForState(state, mode){
    const previousLayout = layout;
    layout = state.layout || layout;
    try{
      const measureCanvas = document.createElement('canvas');
      const measureContext = measureCanvas.getContext('2d');
      if(!measureContext) throw new Error('Canvas 측정 컨텍스트를 만들 수 없습니다.');

      const model = buildModel(state, measureContext);
      const requestedScale = mode === 'original'
        ? image.naturalWidth / 1000
        : 1600 / Math.max(model.width, model.height);

      const pixelLimit = safeCanvasPixelLimit();
      const requestedPixels = model.width * model.height * requestedScale * requestedScale;
      let scale = requestedScale;
      let sizeWasReduced = false;

      if(requestedPixels > pixelLimit){
        scale = Math.sqrt(pixelLimit / (model.width * model.height));
        sizeWasReduced = true;
      }

      const out = document.createElement('canvas');
      out.width = Math.max(1, Math.round(model.width * scale));
      out.height = Math.max(1, Math.round(model.height * scale));

      const outputContext = out.getContext('2d');
      if(!outputContext) throw new Error('출력 Canvas를 만들 수 없습니다.');

      outputContext.setTransform(scale, 0, 0, scale, 0, 0);
      model.draw(outputContext);
      drawUniversalOverlays(outputContext, state, model);

      const dataUrl = out.toDataURL('image/jpeg', 0.95);
      if(!dataUrl || dataUrl === 'data:,') throw new Error('브라우저가 JPEG 데이터를 만들지 못했습니다.');

      const blob = dataUrlToBlob(dataUrl);
      if(!blob || blob.size === 0) throw new Error('생성된 JPEG 데이터가 비어 있습니다.');

      return {blob, width: out.width, height: out.height, sizeWasReduced};
    }finally{
      layout = previousLayout;
    }
  }

  async function exportAllJPEG(mode){
    if(!photoItems.length){
      alert('먼저 사진을 불러와 주세요.');
      return;
    }

    const canZip = typeof JSZip !== 'undefined';
    const canDirectorySave = directoryPickerSupported();
    if(!canZip && !canDirectorySave){
      alert('이 브라우저에서는 ZIP과 폴더 저장을 모두 사용할 수 없습니다. Chrome 또는 Edge 사용을 권장합니다.');
      return;
    }

    if(!selectedUserFontsAreReady()){
      ensureSelectedUserFonts({render:true, silent:false});
      alert(pendingFontLoads ? '선택한 추가 폰트를 불러오는 중입니다. 적용 완료 후 다시 저장하세요.' : '선택한 추가 폰트 파일을 먼저 불러오거나 assets/fonts 폴더에 넣어주세요.');
      return;
    }

    syncCurrentPhotoValues();
    $('downloadResult').hidden = true;

    const initialState = getState();
    const originalSelectedId = selectedPhotoId;
    const originalStatus = $('statusText').textContent;
    const dirHandle = await getExportDirectoryHandle({promptIfNeeded:false});
    const useDirectorySave = !!dirHandle;

    if(!useDirectorySave && !canZip){
      alert('ZIP 라이브러리를 불러오지 못했습니다. 먼저 저장 폴더를 선택한 뒤 다시 시도해 주세요.');
      return;
    }

    const zip = useDirectorySave ? null : new JSZip();
    let reducedCount = 0;
    let savedCount = 0;

    try{
      for(let index=0; index<photoItems.length; index++){
        const item = photoItems[index];
        $('statusText').textContent = `일괄 ${mode === 'original' ? '원본' : '웹용'} ${useDirectorySave ? '저장' : '렌더링'} 중… (${index + 1}/${photoItems.length})`;
        await loadPreviewImageFromItem(item);
        const state = buildStateForPhoto(initialState, item);
        const rendered = generateJPEGBlobForState(state, mode);
        if(rendered.sizeWasReduced) reducedCount += 1;
        const base = (item.name || `photo_${index+1}`).replace(/\.[^.]+$/, '');
        const suffix = rendered.sizeWasReduced && mode === 'original' ? 'original_browser_safe' : mode;
        const finalFileName = `${base}_${state.layout || layout}_${suffix}.jpg`;

        if(useDirectorySave){
          await writeBlobToDirectory(dirHandle, finalFileName, rendered.blob);
          savedCount += 1;
        }else{
          zip.file(finalFileName, rendered.blob, {binary:true});
        }

        await new Promise(resolve => setTimeout(resolve, 0));
      }

      if(useDirectorySave){
        const detail = reducedCount > 0 && mode === 'original'
          ? `${savedCount}장 저장 완료 · ${reducedCount}장은 브라우저 안전 크기로 자동 축소`
          : `${savedCount}장 저장 완료`;
        $('downloadResult').hidden = true;
        $('statusText').textContent = '일괄 폴더 저장 완료';
        $('canvasInfo').textContent = `${savedCount} images saved`;
        updateSaveDirStatus(`저장 폴더: ${dirHandle.name} · ${detail}`);
      }else{
        $('statusText').textContent = 'ZIP 묶는 중…';
        const zipBlob = await zip.generateAsync({type:'blob', streamFiles:true}, meta => {
          $('statusText').textContent = `ZIP 묶는 중… ${Math.round(meta.percent)}%`;
        });

        const zipName = `FrameNote_${batchApplyMode ? layout : 'individual'}_${mode}_batch_${photoItems.length}images.zip`;
        const detail = reducedCount > 0 && mode === 'original'
          ? `원본 모드 중 ${reducedCount}장은 브라우저 안전 크기로 자동 축소`
          : `${photoItems.length}장 순차 처리 완료`;
        prepareAndStartDownload(zipBlob, zipName, `${detail} · 자동 저장이 안 되면 다운로드 버튼을 눌러주세요.`, 'ZIP 다운로드');
        $('statusText').textContent = '일괄 ZIP 생성 완료';
        $('canvasInfo').textContent = `${photoItems.length} images batched`;
      }
    }catch(error){
      console.error('Batch export failed:', error);
      $('statusText').textContent = useDirectorySave ? '일괄 폴더 저장 실패' : '일괄 ZIP 생성 실패';
      alert(`일괄 내보내기에 실패했습니다.

${error && error.message ? error.message : String(error)}`);
    }finally{
      if(originalSelectedId){
        try{ await selectPhotoById(originalSelectedId, {preserveCurrent:false}); }catch(error){ console.warn(error); }
      }
      $('statusText').textContent = $('statusText').textContent.includes('실패') || $('statusText').textContent.includes('완료') ? $('statusText').textContent : originalStatus;
    }
  }

